import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_SANTA_FE: Article[] = [
  { id: 'const-santa-fe-art-1', lawId: 'const-santa-fe', number: '1', title: '', text: `La Provincia de Santa Fe, como miembro del Estado federal argentino, y con la población y el territorio que por derecho le corresponden, organiza sus instituciones fundamentales conforme a los principios democráticos, representativo y republicano, de la sumisión del Estado a las propias normas jurídicas en cualquier campo de su actividad y de los deberes de solidaridad recíproca de los miembros de la colectividad, de acuerdo con las condiciones y limitaciones emergentes de la Constitución Nacional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-2', lawId: 'const-santa-fe', number: '2', title: '', text: `El pueblo y los órganos del Estado que él elige y ejercen la potestad de gobierno están sometidos a los límites que establecen esta Constitución, la Constitución Nacional, los instrumentos internacionales con jerarquía constitucional, los demás tratados internacionales ratificados por el Estado argentino y las leyes dictadas en su consecuencia. La soberanía reside en el pueblo y emana exclusivamente de él. Nadie puede atribuirse legítimamente su ejercicio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 1, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-3', lawId: 'const-santa-fe', number: '3', title: '', text: `La Provincia asegura la distinción entre el Estado y el orden religioso y no establece religión oficial. La relación entre el Estado, la Iglesia Católica, las iglesias y los cultos legalmente reconocidos se rige por los principios de autonomía, igualdad, no discriminación, cooperación y neutralidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 2, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-4', lawId: 'const-santa-fe', number: '4', title: '', text: `La Provincia ratifica demanera irrenunciable la legítima e imprescriptible soberanía argentina sobre las Islas Malvinas, Georgias del Sur y Sandwich del Sur, los espaciosmarítimos e insulares correspondientes, su proyección antártica y su plataforma continental, por ser parte integrante del territorio nacional. La recuperación de esos territorios, la restitución de la integridad territorial, el ejercicio pleno de la soberanía y el respeto delmodo de vida de sus habitantes, conforme a los principios del derecho internacional, constituyen objetivos permanentes e irrenunciables. La Provincia promueve e implementa políticas activas para la protección de los veteranos de guerra y políticas educativas para el ejercicio de la memoria activa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 3, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-5', lawId: 'const-santa-fe', number: '5', title: '', text: `La Provincia garantiza la plena vigencia de sus instituciones democráticas, en orden a mantener su imperio aun cuando se interrumpa o se intente interrumpir su observancia por actos de fuerza contra el orden institucional o el sistema democrático o se usurpen o prorroguen funciones o poderes en violación del régimen constitucional. Estos actos son nulos, de nulidad absoluta e insanable. Quienes los lleven adelante, ordenen, ejecuten o consientan serán pasibles de inhabilitación absoluta y perpetua para ocupar cargos públicos y quedarán excluidos de los beneficios de la conmutación de penas y del indulto. Toda persona tiene derecho de resistencia contra quienes ejecuten los actos de fuerza enunciados. Atenta contra el sistema democrático quien incurra en grave delito doloso contra el Estado que implique enriquecimiento. Estos actos conllevan inhabilitación para ocupar cargos o empleos públicos por el tiempo que las leyes determinan. La Provincia garantiza la existencia de mecanismos independientes y autónomos destinados a promover la transparencia, prevenir y disuadir hechos de corrupción y fortalecer la ética pública en la gestión. La Provincia sostiene el respeto a los símbolos patrios y a su bandera.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 4, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-6', lawId: 'const-santa-fe', number: '6', title: '', text: `Los órganos de la Provincia observan los principios de integridad, transparencia y rendición de cuentas. Sus funcionarios y agentes ejercen su función de conformidad con la ley de ética pública y están obligados a presentar información patrimonial y de conflictos de intereses en forma actualizada y pública, según disponga la ley. Las inmunidades establecidas por esta Constitución y las leyes solo se aplican a los sujetos y con el alcance previsto. No se pueden establecer inmunidades más amplias. Se garantiza el acceso a la justicia y la resolución de conflictos en un plazo razonable. Se deben establecermecanismos que permitan accionar para garantizar los principios democráticos y republicanos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 5, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-7', lawId: 'const-santa-fe', number: '7', title: '', text: `Las autoridades que ejercen elGobierno Provincial residen en la ciudad de Santa Fe, Capital de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 6, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-8', lawId: 'const-santa-fe', number: '8', title: '', text: `La Provincia sostiene el gasto público mediante los recursos provenientes de la coparticipación federal, la recaudación de los tributos creados por ley, las rentas producidas por sus bienes y servicios, la enajenación de sus activos o bienes de su pertenencia, la propia actividad económica que desarrolle y las operaciones de crédito que concierte que no pueden destinarse a financiar gastos corrientes, salvo en caso de urgencia. Toda persona que habita la Provincia o que en ella desarrolla actividad económica está obligada a concurrir a los gastos públicos. El sistema tributario se organiza considerando la función económica y social de los tributos y se inspira en los principios de legalidad, generalidad, no confiscatoriedad, irretroactividad, igualdad, equidad, razonabilidad, capacidad contributiva, simplicidad y certeza. Puede establecer estructuras progresivas de alícuotas, exenciones y otras disposiciones tendientes a graduar la carga fiscal para lograr el desarrollo económico, territorial y social de la comunidad. Puede contemplar un tratamiento fiscal diferenciado para las cooperativas y mutuales que, en cumplimiento de las formalidades y exigencias legales, acrediten su naturaleza de entidades sin fines de lucro y su función social dentro de la economía solidaria. Los tributos deben ser creados por ley. Es nula toda delegación expresa o tácita. La administración financiera y presupuestaria se rige por los principios de responsabilidad fiscal, sostenibilidad, eficiencia, eficacia, publicidad y transparencia. Garantiza mecanismos de control y rendición de cuentas. La ley establece reglas, estándares, procedimientos y dispositivos institucionales vinculados con el gasto, la deuda pública y la transparencia, que tiendan al equilibrio fiscal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 7, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-9', lawId: 'const-santa-fe', number: '9', title: '', text: `La Provincia y los municipios son responsables por los daños que ocasionen. La ley determina los supuestos y el alcance de la responsabilidad del Estado y los casos en que corresponda la obligación de reembolso de sus funcionarios o agentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 8, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-10', lawId: 'const-santa-fe', number: '10', title: '', text: `El Estado reconoce a la persona humana su eminente dignidad y todos los órganos del poder público están obligados a respetarla y protegerla. El individuo desenvuelve libremente su personalidad, ya en forma aislada, ya en forma asociada, en el ejercicio de los derechos inviolables que le competen. La persona puede siempre defender sus derechos e intereses legítimos, de cualquier naturaleza, ante los poderes públicos, de acuerdo con las leyes respectivas. Los derechos fundamentales de libertad y sus garantías reconocidos por esta Constitución son directamente operativos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 9, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-11', lawId: 'const-santa-fe', number: '11', title: '', text: `Los habitantes de la Provincia, nacionales y extranjeros, gozan en su territorio de todos los derechos y garantías que les reconocen la Constitución Nacional y la presente, inclusive de aquellos no previstos en ambas y que nacen de los principios que las inspiran.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 10, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-12', lawId: 'const-santa-fe', number: '12', title: '', text: `Todos los habitantes de la Provincia son iguales ante la ley. Incumbe al Estado remover los obstáculos de orden económico y social que, limitando de hecho la igualdad y la libertad de los individuos, impidan el libre desarrollo de la persona humana y la efectiva participación de todos en la vida política, económica y social de la comunidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 11, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-13', lawId: 'const-santa-fe', number: '13', title: '', text: `La Provincia reconoce la existencia de desigualdades estructurales que limitan el goce pleno de los derechos de las personas. Se compromete a adoptar medidas de acción positiva para reducir sus efectos negativos y garantizar condiciones de igualdad y no discriminación, en especial, y sin perjuicio de otros grupos que se encuentren en situación de desventaja estructural, respecto a: 1) la protección integral de las niñas, niños y adolescentes, atendiendo a su interés superior y al derecho a ser escuchados de acuerdo con su autonomía progresiva; 2) el principio de participación paritaria de las mujeres, la igualdad sustantiva de ellas y las diversidades en todos los ámbitos, garantizando la protección integral frente a toda forma de violencia y discriminación; 3) el rol activo de las juventudes en la vida social, económica, política y cultural, asegurando mecanismos institucionales para la real participación y toma de decisiones; 4) el cuidado de las personas mayores que preserve su dignidad, autonomía, independencia y el respeto a su proyecto de vida; 5) la participación plena y efectiva de las personas con discapacidad, promoviendo los apoyos y ajustes razonables con enfoque de diseño universal y accesibilidad; 6) la preexistencia y persistencia étnica y cultural de los pueblos indígenas y sus comunidades; 7) el abordaje de la indigencia, la pobreza y la exclusión; ?, 8) la promoción de la equidad territorial para superar la discriminación por razones geográficas en la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 12, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-14', lawId: 'const-santa-fe', number: '14', title: '', text: `Toda persona tiene derecho a la libertad personal y no puede ser privada de ella ni restringido su ejercicio, sino por disposición de autoridad competente en los casos y condiciones previstos con anterioridad por la ley. En caso de detención, debe darse aviso inmediato a un juez, para que revise la medida en el plazo máximo de veinticuatro horas. No podrá mantenerse una incomunicación por más de cuarenta y ocho horas, salvo resolución judicial. La incomunicación de la persona detenida nunca puede afectar el derecho de comunicación con su abogado defensor. La privación de la libertad durante el proceso tiene carácter excepcional, conforme los criterios y alcances determinados por la ley. Quedan prohibidos la tortura y los tratos crueles, inhumanos o degradantes, y cualquier otra forma de violencia sobre las personas sometidas a privación o restricción de su libertad ambulatoria. Nadie puede ser penado sino en virtud de un proceso y de una típica definición de una acción u omisión culpable previamente establecidos por la ley, ni sacado del tribunal constituido con anterioridad por esta, ni privado del derecho de defensa. No se pueden reabrir procesos fenecidos, sin perjuicio de la revisión favorable de sentencias penales en los casos previstos por la ley procesal. Los establecimientos de privación de libertad deben ser sanos y limpios, adoptando las medidas necesarias para otorgar un trato adecuado conforme a la situación procesal, el género y la edad. Las personas menores de edad deben ser alojadas en lugares diferentes a los destinados a personas adultas. En materia penal se instituye el proceso acusatorio, adversarial, oral y público. La ley determina los casos criminales que deben ser juzgados por jurados populares clásicos; y propende a la implementación progresiva del juicio oral y por jurados en los demás procesos judiciales, en las mismas condiciones que el jurado penal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 13, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-15', lawId: 'const-santa-fe', number: '15', title: '', text: `El domicilio es inviolable. No se puede efectuar en él registros, inspecciones o secuestros sino en los casos y en las condiciones que fije la ley. Son igualmente inviolables la libertad y el secreto de la correspondencia y de todo otro medio de comunicación y sus restricciones pueden realizarse sólo cuando la ley las autorice y con sus garantías. Los habitantes de la Provincia pueden permanecer y circular libremente en su territorio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 14, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-16', lawId: 'const-santa-fe', number: '16', title: '', text: `Toda persona tiene derecho a la libertad de pensamiento y a expresar y difundir sus ideas por cualquier medio sin censura previa. Solo puede ser sometida a las responsabilidades ulteriores que establezca la ley por razones de interés general. La violencia discursiva, en entornos digitales o en cualquier otro medio, constituye una forma de deterioro del debate público democrático. La Provincia promueve y garantiza la pluralidad de voces. La actividad periodística, ejercida de conformidad con sus pautas éticas, se encuentra especialmente protegida como componente fundamental del sistema democrático. Están prohibidas las formas indirectas de censura y la afectación del secreto de las fuentes de información periodística. Quien resulte perjudicado por informaciones inexactas o agraviantes emitidas a través de medios de comunicación tiene derecho de rectificación o respuesta gratuita, con idénticos alcances y en las condiciones que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 15, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-17', lawId: 'const-santa-fe', number: '17', title: '', text: `Toda persona tiene derecho a buscar, recibir y difundir información. La Provincia garantiza el derecho de acceso a la información pública, la que debe ser suministrada sin dilaciones, de manera clara, completa y concreta, guiada por el principio de máxima divulgación, sin más limitaciones que las que establezca la ley en resguardo de la seguridad pública y la intimidad de las personas. Todo órgano del Estado que deniegue la información está obligado a fundamentar dicha decisión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 16, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-18', lawId: 'const-santa-fe', number: '18', title: '', text: `Todos gozan del derecho a la libre profesión de su fe religiosa en forma individual o asociada, a hacer propaganda de ella y a ejercer el culto en público o privado, salvo que sea contrario al orden público o a las buenas costumbres. No se puede suprimir o limitar el ejercicio de un derecho en razón de profesarse determinada religión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 17, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-19', lawId: 'const-santa-fe', number: '19', title: '', text: `Todas las personas tienen derecho a reunirse y a manifestarse en forma pacífica; a asociarse libremente con fines lícitos, salvo las restricciones que la ley prevea; a peticionar ante las autoridades públicas y a obtener una pronta respuesta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 18, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-20', lawId: 'const-santa-fe', number: '20', title: '', text: `Todos tienen derecho a ejercer, según las propias posibilidades y la propia elección, una actividad o profesión que concurra al progreso material o espiritual de la sociedad, en las condiciones que establezca la ley. Pueden, asimismo, tener acceso a los cargos públicos en condiciones de igualdad, según los requisitos que se determinen. Ninguna prestación personal de servicios al Estado es exigible sino en virtud de la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 19, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-21', lawId: 'const-santa-fe', number: '21', title: '', text: `La propiedad privada es inviolable y solamente puede ser limitada con el fin que cumpla una función social. El Estado puede expropiar bienes, previa indemnización, por motivos de interés general calificado por ley. La iniciativa económica de los individuos es libre. Sin embargo, no puede desarrollarse en pugna con la utilidad social o con mengua de la seguridad, libertad o dignidad humana. En este sentido, la ley puede limitarla, con medidas que encuadren en la potestad de gobierno local. Ninguna prestación patrimonial puede ser impuesta sino conforme a la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 20, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-22', lawId: 'const-santa-fe', number: '22', title: '', text: `Toda persona tiene derecho al cuidado integral de su salud en todos los ciclos de la vida, que incluye los aspectos físico, mental, emocional, ambiental y social; y a decidir sobre su propia salud siempre que no afecte la salud colectiva. La Provincia tutela la salud como derecho fundamental del individuo e interés de la comunidad. Adopta acciones de prevención, atención, recuperación y rehabilitación de la salud en todos los niveles, con base en la atención primaria y con criterios de universalidad, gratuidad, adecuación, equidad, interdisciplinariedad y oportunidad. La Provincia sostiene un sistema de atención público, gratuito y de calidad. Puede establecer mecanismos de recuperación de los costos de la atención de salud prestada, a obras sociales, prestadoras de servicios de salud u otros sistemas de aseguramiento, en los casos que corresponda. Regula, articula y fiscaliza todas las acciones y prestaciones de salud en su territorio y concreta la política de salud en coordinación con los otros niveles gubernamentales y otras entidades públicas o privadas. El medicamento es considerado un bien social y la Provincia reconoce el interés en su producción pública. La Provincia promueve la educación, formación y capacitación en salud y reconoce la función social de sus trabajadores. Estimula la investigación biomédica sobre los principales problemas de salud, respetando la dignidad de las personas. La Provincia impulsa la actividad física, recreativa o deportiva, junto con la alimentación saludable como herramientas esenciales para la prevención de enfermedades, la promoción de la salud, la inclusión, la integración social y el desarrollo de la persona.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 21, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-23', lawId: 'const-santa-fe', number: '23', title: '', text: `Toda persona tiene derecho al trabajo como base del bienestar individual y colectivo. El trabajo constituye un derecho humano y un deber social. La Provincia promueve el trabajo decente y condiciones de empleo equitativas, satisfactorias y seguras, que respeten la dignidad humana, la libertad y la igualdad de oportunidades. Reconoce al trabajador como sujeto de tutela preferente y promueve el empleo registrado. La Provincia impulsa políticas activas de empleo, capacitación continua y transición productiva profesional que favorezcan la inserción laboral, la inclusión y la empleabilidad de las personas, especialmente de los grupos en situación de vulnerabilidad. Se deben considerar las transformaciones del mundo del trabajo, las nuevas formas de empleo, la economía social, el trabajo asociativo, el avance tecnológico y los requerimientos para un desarrollo socioeconómico sostenible e inclusivo. Los trabajadores tienen derecho a un salario justo, a igual remuneración por igual tarea, a la jornada limitada, al descanso, a la desconexión digital, a vacaciones pagas, a seguridad e higiene en el ámbito laboral. El ingreso al empleo público se funda en criterios de igualdad e idoneidad y no se admite prerrogativa alguna. La Provincia impulsa la erradicación del acoso y toda forma de violencia laboral, en especial la violencia de género; la prevención y eliminación del trabajo infantil en todas sus formas, el trabajo forzoso y la trata de personas. La Provincia reconoce y protege el derecho de asociación y de expresarse con libertad respecto a su trabajo. Asegura la libertad sindical, la tutela sindical, la negociación colectiva y el derecho de huelga. Fortalece mecanismos administrativos y judiciales ágiles y efectivos para la prevención y resolución de los conflictos laborales y establece tribunales especializados en materia laboral, con procedimientos concentrados, gratuitos y que propendan a la oralidad, para garantizar el acceso efectivo a la justicia de quienes trabajan y de sus organizaciones. La Provincia reconoce a las personas humanas y jurídicas que generan empleo en el ámbito privado como actores fundamentales del desarrollo productivo y social. Promueve y protege su actividad, con especial atención a las micro, pequeñas y medianas unidades económicas. Vigila que los empleadores respeten los derechos laborales y obren con debida diligencia, en resguardo del interés público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 22, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-24', lawId: 'const-santa-fe', number: '24', title: '', text: `Toda persona tiene derecho a un nivel de vida adecuado que asegure su bienestar y el de su familia; a una alimentación nutritiva, diaria, suficiente, segura y de calidad; a la vestimenta; a la vivienda y a los cuidados médicos y servicios sociales necesarios que le permitan gozar de una vida digna. La Provincia reconoce el valor social y económico de las tareas de cuidado e impulsa acciones que promueven el cuidado digno a lo largo de la vida, con especial atención a las personas en situación de vulnerabilidad. Toda persona tiene derecho a la provisión de los medios adecuados para el desarrollo de su vida si está impedida de trabajar y carece de los recursos indispensables. En su caso, tiene derecho a la readaptación y rehabilitación profesional. La Provincia organiza un sistema de seguridad social con carácter integral e irrenunciable, basado en los principios de solidaridad, equidad distributiva, accesibilidad, sostenibilidad y transparencia, destinado a la protección de las personas ante contingencias, conforme con las leyes que lo reglamenten. El sistema previsional de los agentes públicos del Estado provincial se financia mediante un mecanismo de reparto solidario de carácter público. Las jubilaciones y pensiones son móviles. La administración está a cargo de un órgano intransferible. La sustentabilidad del sistema se asegura mediante acciones progresivas, equitativas y razonables. Los recursos que integran el patrimonio de las cajas de previsión y seguridad social son intangibles y no pueden destinarse a otros fines.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 23, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-25', lawId: 'const-santa-fe', number: '25', title: '', text: `La Provincia contribuye a la formación y defensa integral de la familia y al cumplimiento de las funciones que le son propias con medidas económicas o de cualquier otra índole encuadradas en la esfera de sus poderes. Procura que el niño crezca bajo la responsabilidad y amparo del núcleo familiar. Protege en lo material y moral la maternidad, la infancia, la juventud y la ancianidad, directamente o fomentando las instituciones privadas orientadas a tal fin.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 24, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-26', lawId: 'const-santa-fe', number: '26', title: '', text: `Toda persona tiene derecho a participar y a gozar en condiciones de igualdad de la vida cultural, a expresar libremente su identidad y a ejercer sus derechos culturales sin discriminación. La Provincia garantiza el respeto por la diversidad cultural, promueve el diálogo intercultural, la libre creación y expresión artística y la difusión de la cultura local en sus múltiples formas y manifestaciones. Articula las relaciones entre el sector público, privado y comunitario para la promoción y sostenibilidad de proyectos culturales y estimula la inversión con criterios de equidad territorial, inclusión social y pluralismo. Las personas y comunidades gozan del derecho colectivo al disfrute, acceso, conservación y transmisión del patrimonio cultural material e inmaterial de carácter histórico, artístico, arquitectónico, arqueológico y paleontológico. La Provincia protege, preserva, promueve y desarrolla dicho patrimonio y adopta medidas para garantizar su sostenibilidad y su transmisión a las futuras generaciones. Toda persona tiene el deber de respetar y cooperar con la preservación y valoración del patrimonio cultural. La Provincia respalda y fomenta las actividades y el funcionamiento de las bibliotecas públicas y bibliotecas populares. Los sitios, archivos y espacios de memoria forman parte del patrimonio cultural de la Provincia y el Estado garantiza su preservación, señalización y promoción activa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 25, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-27', lawId: 'const-santa-fe', number: '27', title: '', text: `La Provincia reconoce a la ciencia, la tecnología y la innovación como un bien común, un derecho de las personas y una herramienta estratégica para el desarrollo socio productivo, sostenible e inclusivo. Impulsa el fortalecimiento de un sistema de innovación a través del desarrollo de una institucionalidad, de políticas públicas y de recursos que aseguren el acceso equitativo a sus beneficios, el impulso a la investigación original, la transferencia tecnológica y la difusión del conocimiento. Propicia la articulación entre actores públicos y privados vinculados a la generación de conocimiento en particular con universidades y organismos de ciencia y tecnología.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 26, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-28', lawId: 'const-santa-fe', number: '28', title: '', text: `Los derechos previstos en esta Constitución son aplicables en entornos digitales. La Provincia impulsa el desarrollo y uso ético de las tecnologías de manera segura y orientados al bien común, preservando la centralidad y la dignidad de la persona humana. Toda persona tiene derecho al acceso universal, equitativo, asequible, sin discriminación, continuo y de calidad a la tecnología, a la conectividad y a la infraestructura tecnológica. El Estado adopta medidas para la eliminación de las brechas digitales y para lograr progresivamente la efectividad de este derecho que se reconoce como condición para el ejercicio de una ciudadanía plena e igualitaria. La Provincia promueve la construcción de una ciudadanía digital inclusiva, la alfabetización digital crítica, el respeto a la privacidad, la autonomía mental y la no manipulación de pensamientos, emociones, acciones o decisiones mediante el uso de tecnologías. El consentimiento debe ser libre, expreso, informado y revocable. Adopta políticas integrales de ciberseguridad. Procura un espacio digital libre de violencia, con especial protección de niños, niñas y adolescentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 27, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-29', lawId: 'const-santa-fe', number: '29', title: '', text: `Toda persona tiene derecho a la protección de sus datos personales en entornos digitales y ejerce sobre ellos el control en el uso, gestión, circulación y conservación de su información personal. Toda persona tiene derecho a conocer de forma clara, accesible y comprensible los criterios, parámetros y lógicas utilizadas en los sistemas automatizados o algorítmicos de toma de decisiones y a la intervención de una persona humana cuando esa decisión pueda afectar sus derechos, especialmente en los que se implemente inteligencia artificial u otras tecnologías emergentes. La Provincia o los terceros que presten servicios de interés público deben adoptar sistemas algorítmicos transparentes y auditables y promover mecanismos de evaluación de impacto y resguardo frente a sesgos o discriminación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 28, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-30', lawId: 'const-santa-fe', number: '30', title: '', text: `Toda persona tiene derecho a vivir en un entorno físico y digital seguro, libre de violencias y amenazas. La seguridad pública y ciudadana es un deber indelegable e irrenunciable de la Provincia dirigido a mantener el orden público democrático, las instituciones y la seguridad de personas y bienes, que procure el pleno disfrute y ejercicio de derechos y libertades. La Provincia promueve políticas públicas integrales, multidisciplinarias e inclusivas para la protección de la vida, la integridad personal, la libertad, los bienes, la convivencia pacífica y el pleno ejercicio de los derechos fundamentales. Se fundan en la planificación estratégica, la producción y análisis de información, la evaluación de resultados, la articulación con la Nación y los gobiernos locales y la participación de la comunidad. Las fuerzas de seguridad y demás órganos encargados de velar por la seguridad ciudadana son instituciones esenciales de la sociedad y son responsables del mantenimiento del orden, la prevención del delito y la actuación ante emergencias. La Provincia garantiza la capacitación continua y la profesionalización de quienes integran las fuerzas de seguridad y promueve políticas de integridad, transparencia y rendición de cuentas en su funcionamiento. La Provincia ejerce el monopolio de la fuerza, la que es siempre excepcional y conforme al ordenamiento jurídico, normas constitucionales y convencionales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 29, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-31', lawId: 'const-santa-fe', number: '31', title: '', text: `Las víctimas de delitos y, en su caso, sus familiares tienen derecho a un trato digno y respetuoso de su intimidad, al acceso a la justicia, a ser informados de manera clara y oportuna sobre sus derechos y a conocer el estado de la investigación, el proceso penal y las decisiones que se adopten. Tienen derecho a participar en el proceso penal en forma activa en las condiciones que determine la ley. El Estado procura su debida asistencia, evitando conductas discriminatorias y cualquier forma de revictimización. La debida diligencia en el proceso judicial será reforzada cuando las víctimas sean personas en situación de vulnerabilidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 30, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-32', lawId: 'const-santa-fe', number: '32', title: '', text: `La Provincia protege los derechos de consumidores y usuarios. Gozan en sus relaciones de consumo de los siguientes derechos: a la dignidad; a la educación; al acceso al consumo sustentable, seguro y de calidad; a la salud; a la protección de su privacidad; a la indemnidad personal y patrimonial, conforme los principios de prevención, precaución y de reparación integral; a la información; al acceso gratuito a la justicia y tutela judicial efectiva; y a asociarse para la defensa de estos derechos. La Provincia protege estos derechos mediante un sistema administrativo de defensa del consumidor, su normativa de implementación y las acciones judiciales individuales y colectivas. Adopta, en coordinación con los municipios, medidas de educación para el consumo, de promoción de asociaciones de consumidores y usuarios, de consumo sustentable, de prevención de conflictos y de riesgos en el entorno físico y digital; y especialmente para los consumidores y usuarios hipervulnerables de protección contra los riesgos de la publicidad, del sobreendeudamiento y de las cláusulas contractuales y prácticas abusivas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 31, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-33', lawId: 'const-santa-fe', number: '33', title: '', text: `Toda persona tiene derecho a gozar de un ambiente sano, equilibrado, sostenible y apto para el desarrollo humano y el deber de cuidarlo y protegerlo con enfoque intergeneracional y colaborar con la acción climática. Su cuidado constituye una responsabilidad compartida entre la Provincia, la ciudadanía y los sectores productivos. El ambiente es un bien colectivo y la Provincia establece políticas públicas de protección con base en los principios de prevención, precaución, equidad intergeneracional, progresividad y no regresividad, responsabilidad y solidaridad. La Provincia protege la naturaleza, las áreas naturales, las especies nativas, los ecosistemas y los animales. Impulsa la sostenibilidad ambiental, social y económica de las actividades públicas y privadas y adopta las medidas necesarias ante un daño significativo al ambiente, conforme lo determine la ley. Debe establecer de manera progresiva una política climática que incluya mitigación y adaptación al cambio climático y que contemple herramientas para la prevención, una transición justa y el logro de mayor resiliencia. El daño ambiental genera prioritariamente la obligación de recomponer, según lo establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 32, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-34', lawId: 'const-santa-fe', number: '34', title: '', text: `El agua es un bien colectivo de uso común e indivisible, esencial para la vida humana, de los ecosistemas y para el desarrollo productivo. Tiene función social y ambiental y goza de especial protección desde una perspectiva sistémica. Toda persona tiene derecho de acceso universal y asequible al agua potable y al saneamiento. La Provincia estructura la política pública de gestión integrada, sostenible y planificada de los recursos hídricos con base en la seguridad hídrica, la equidad intergeneracional, el ordenamiento territorial, el establecimiento de cuencas hidrográficas, la preservación del ciclo hidrológico y de los humedales, la interpretación más favorable a la protección de los recursos de agua y ecosistemas conexos, la información pública y la participación ciudadana. La Provincia puede celebrar acuerdos con otras jurisdicciones para la elaboración, implementación y evaluación de políticas de gestión, desarrollo y preservación de las cuencas interjurisdiccionales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 33, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-35', lawId: 'const-santa-fe', number: '35', title: '', text: `La Provincia reconoce el derecho a la ciudad fundado en el uso pleno y equitativo, en su función social y ambiental, en los principios de participación ciudadana, gestión democrática, justicia espacial, equidad social e intergeneracional y respeto a la diversidad cultural. La Provincia favorece el arraigo poblacional mediante políticas de integración territorial, la vinculación del entorno urbano y rural y el acceso equitativo al hábitat digno. Impulsa el derecho a la movilidad y sistemas de transporte integrados, accesibles, seguros y sostenibles; la integración socio-urbana; los sistemas de gestión integral de riesgos; y la recuperación del incremento del valor en bienes privados producidos por inversión o decisión estatal, urbanización o planificación públicas para financiar infraestructuras, servicios y ordenamiento territorial y ambiental de acuerdo con lo dispuesto por la normativa. Promueve políticas especiales para el desarrollo sostenible de ciudades pequeñas e intermedias y generar impactos económicos, sociales y ambientales positivos en zonas urbanas, periurbanas y rurales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 34, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-36', lawId: 'const-santa-fe', number: '36', title: '', text: `El individuo tiene deberes hacia la comunidad. En el ejercicio de sus derechos y en el disfrute de sus libertades puede quedar sometido a las limitaciones, establecidas por la ley exclusivamente, necesarias para asegurar el respeto de los derechos y libertades ajenas y satisfacer las justas exigencias de la moral y el orden público y del bienestar general.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 35, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-37', lawId: 'const-santa-fe', number: '37', title: '', text: `Toda persona tiene derecho a la educación, que comprende la igualdad en el acceso, los aprendizajes y el egreso, desde una perspectiva de derechos humanos. La Provincia garantiza el derecho de enseñar y aprender mediante la organización y dirección de un sistema educativo único, articulado en todos sus niveles, modalidades y tipos de gestión. El Estado asume la responsabilidad intransferible e indelegable de garantizar el derecho a la educación gratuita, laica, universal, plural, inclusiva, científica, de calidad y democrática. Los niveles inicial, primario y secundario son obligatorios, de conformidad con el ordenamiento jurídico. La educación superior es promovida en función del proyecto de vida de cada persona y en articulación con las necesidades sociales, productivas, científicas y culturales. La Provincia dispondrá de dispositivos de evaluación de resultados de los aprendizajes a los fines de asegurar el ejercicio pleno de este derecho.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 36, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-38', lawId: 'const-santa-fe', number: '38', title: '', text: `La Provincia reconoce el derecho a la creación de escuelas e institutos educativos de gestión privada. Estos establecimientos desarrollan el contenido de los diseños curriculares oficiales y se adecúan, como mínimo, a los principios de universalidad, calidad, inclusión, cientificidad, democracia y al ordenamiento jurídico. De conformidad con ello, se garantiza el derecho de las familias a elegir el tipo de educación según sus convicciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 37, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-39', lawId: 'const-santa-fe', number: '39', title: '', text: `La Provincia promueve la articulación entre la educación y el trabajo como componente fundamental para la formación integral de las personas y asegura trayectorias educativas que favorezcan la inserción y el desarrollo laboral digno. Arbitra las medidas para procurar la permanencia y reducir la deserción escolar. La Provincia promueve la alfabetización digital y el acceso equitativo a tecnologías de la información para la democratización del conocimiento, la educación ambiental y la promoción de la salud.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 38, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-40', lawId: 'const-santa-fe', number: '40', title: '', text: `El Estado estimula la formación de entidades privadas de cooperación con los institutos educativos oficiales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 39, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-41', lawId: 'const-santa-fe', number: '41', title: '', text: `La Provincia tiene la responsabilidad indelegable de destinar los recursos suficientes para el sostenimiento del sistema educativo. Los docentes y trabajadores de la educación tienen derecho a condiciones dignas de trabajo y formación profesional continua. En la gestión oficial se aseguran el ingreso objetivo a la carrera profesional; los concursos públicos, abiertos y transparentes; y la estabilidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 40, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-42', lawId: 'const-santa-fe', number: '42', title: '', text: `Toda persona que, de modo actual o inminente, sufra de manera ilegal o arbitraria cualquier tipo de privación, restricción o amenaza en su libertad personal, puede ejercer la garantía de habeas corpus recurriendo ante cualquier juez por la acción más expedita y rápida. También puede ejercerla en caso de agravamiento ilegítimo en la forma o las condiciones de detención, o de indeterminación de su lugar, o de desaparición forzada de personas. Esta acción puede ser interpuesta por la persona afectada o por cualquier otra en su favor sin necesidad de mandato expreso. El juez debe resolver de inmediato, aun en situaciones de excepción o de emergencia, y de ser procedente disponer su inmediata cesación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 41, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-43', lawId: 'const-santa-fe', number: '43', title: '', text: `Toda persona tiene derecho a interponer ante los jueces o tribunales acción expedita y rápida de amparo, siempre que no exista otro medio judicial más idóneo y efectivo, contra todo acto u omisión de autoridades o de particulares que en forma actual o inminente lesione, restrinja, altere o amenace, con arbitrariedad o ilegalidad manifiesta, derechos, libertades y garantías reconocidos en esta Constitución, la Constitución de la Nación, un tratado o una ley. Puede también interponerse contra cualquier forma de discriminación y contra la vulneración de derechos que protegen al ambiente, al usuario y al consumidor, así como a derechos de incidencia colectiva en general. Los derechos de incidencia colectiva referidos a intereses individuales homogéneos estarán garantizados mediante la acción de clase. El juez podrá declarar la inconstitucionalidad e inconvencionalidad de la norma en la que se funde el acto u omisión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 42, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-44', lawId: 'const-santa-fe', number: '44', title: '', text: `Toda persona tiene derecho a acceder a sus datos personales registrados en archivos, bancos, bases o registros de datos públicos o privados y de la finalidad de su almacenamiento, así como a requerir su rectificación, actualización, supresión o confidencialidad, en caso de inexactitud, uso indebido o tratamiento lesivo de derechos. Este derecho puede ejercerse mediante una acción rápida de habeas data conforme lo establezca la ley. El tratamiento de datos personales debe respetar los principios de consentimiento, legalidad, finalidad, calidad, seguridad, confidencialidad, proporcionalidad y responsabilidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 43, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-45', lawId: 'const-santa-fe', number: '45', title: '', text: `La Provincia promueve un sistema de gestión pública eficiente, transparente, sostenible y orientado a la generación de valor público. Incentiva la calidad de las políticas públicas basadas en datos y evidencia científica, con respeto a los derechos fundamentales y los principios de relevancia social. Organiza diseños institucionales sustentados en pautas de coordinación interjurisdiccional e intersectorial, participación ciudadana e inclusión de distintas perspectivas. La Provincia impulsa la planificación y la evaluación de políticas públicas; desarrolla acciones concretas que facilitan el análisis de su implementación y la medición del desempeño institucional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 44, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-46', lawId: 'const-santa-fe', number: '46', title: '', text: `La Provincia reconoce a los datos públicos como bienes estratégicos para el desarrollo equitativo e inclusivo, la innovación y la toma de decisiones de un buen gobierno. Debe garantizar una gobernanza democrática basada en los principios de transparencia, trazabilidad, eficiencia, calidad, interoperabilidad, participación social y rendición de cuentas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 45, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-47', lawId: 'const-santa-fe', number: '47', title: '', text: `El Estado provincial promueve el desarrollo e integración económicos de las diferentes zonas de su territorio, en correlación con la economía nacional, y a este fin orienta la iniciativa económica privada y la estimula mediante una adecuada política tributaria y crediticia y la construcción de vías de comunicación, canales, plantas generadoras de energía y demás obras públicas que sean necesarias. Facilita, con igual propósito, la incorporación de capitales, equipos, materiales, asistencia tecnológica y asesoramiento administrativo y, en general, adopta cualquier medida que estime conveniente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 46, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-48', lawId: 'const-santa-fe', number: '48', title: '', text: `La Provincia promueve el federalismo de concertación para facilitar el desarrollo armónico de las relaciones con la Nación, con otras provincias y con la Ciudad Autónoma de Buenos Aires. Se propicia la conformación de regiones junto con otras provincias con intereses comunes con el objeto de potenciar el desarrollo económico, social, productivo e institucional. La actividad portuaria es considerada estratégica, en razón de su carácter fundamental para el desarrollo económico, productivo y comercial. La Provincia impulsa la cooperación y articulación entre los distintos niveles de gobierno para la gestión y desarrollo de los puertos. La Provincia puede celebrar convenios con otras naciones, con entes públicos y privados extranjeros y con organismos internacionales sobre materias no delegadas a la Nación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 47, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-49', lawId: 'const-santa-fe', number: '49', title: '', text: `La Provincia, en coordinación con los ámbitos municipal, intermunicipal y regional, promueve una política integral de planificación y ordenamiento del territorio urbano, periurbano y rural, destinada a favorecer su desarrollo integrado en las dimensiones regional, metropolitana y local. La normativa establece los lineamientos e instrumentos de planificación y ordenamiento territorial con base en criterios de sostenibilidad ambiental, social y económica y con perspectiva climática, con la finalidad de: 1) promover la equidad territorial, el equilibrio entre lo urbano y lo rural; 2) fortalecer los municipios pequeños e intermedios; 3) favorecer el desarrollo urbano sostenible, compacto y eficiente; 4) regular el suelo y sus usos contemplando su función social, ambiental y económica; 5) preservar el ambiente, la calidad paisajística y el patrimonio natural, cultural e histórico; e, 6) impulsar la participación ciudadana.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 48, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-50', lawId: 'const-santa-fe', number: '50', title: '', text: `La Provincia promueve la racional explotación de la tierra por la colonización de las de su propiedad y de los predios no explotados o cuya explotación no se realice conforme a la función social de la propiedad y adquiera por compra o expropiación. Propende a la formación, desarrollo y estabilidad de la población rural por el estímulo y protección del trabajo del campo y de sus productos y el mejoramiento del nivel de vida de sus pobladores. Facilita la formulación y ejecución de planes de transformación agraria para convertir a arrendatarios y aparceros en propietarios y radicar a los productores que carezcan de la posibilidad de lograr por sí mismos el acceso a la propiedad de la tierra. Favorece mediante el asesoramiento y la provisión de los elementos necesarios el adelanto tecnológico de la actividad agropecuaria a fin de obtener una racional explotación del suelo y el incremento y diversificación de la producción. Estimula la industrialización y comercialización de sus productos por organismos cooperativos radicados en las zonas de producción que faciliten su acceso directo a los mercados de consumo, tanto internos como externos, y mediante una adecuada política de promoción, crediticia y tributaria, que aliente la actividad privada realizada con sentido de solidaridad social. Promueve la creación de entes cooperativos que, conjuntamente con otros organismos, al realizar el proceso industrial y comercial, defiendan el valor de la producción del agro de la disparidad de los precios agropecuarios y de los no agropecuarios. Protege el suelo de la degradación y erosión, conserva y restaura la capacidad productiva de las tierras y estimula el perfeccionamiento de las bases técnicas de su laboreo. Resguarda la flora y la fauna autóctonas y proyecta, ejecuta y fiscaliza planes orgánicos y racionales de forestación y reforestación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 49, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-51', lawId: 'const-santa-fe', number: '51', title: '', text: `La Provincia y los municipios establecen, en el ámbito de sus respectivas competencias, marcos regulatorios para la organización, la gestión directa o indirecta y el control de los servicios públicos, de conformidad con los principios de igualdad, universalidad, regularidad, continuidad, obligatoriedad y sostenibilidad. Los marcos regulatorios deben fijar estándares de calidad, eficacia y eficiencia en la prestación, incorporar mecanismos de control, establecer sistemas de protección e incluir instancias de participación para las personas usuarias. La regulación y organización de los servicios públicos promueven el acceso a las prestaciones de acuerdo a su vinculación con otros derechos fundamentales. La Provincia reconoce la importancia estratégica de los servicios públicos para la gestión de recursos, el desarrollo sostenible del territorio y de las actividades productivas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 50, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-52', lawId: 'const-santa-fe', number: '52', title: '', text: `El Estado promueve y coopera en la formación y sostenimiento de entidades privadas que se propongan objetivos científicos, literarios, artísticos, deportivos, de asistencia, de perfección técnica o de solidaridad de intereses.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 51, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-53', lawId: 'const-santa-fe', number: '53', title: '', text: `La Provincia reconoce la existencia de los Colegios y Consejos Profesionales creados por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 52, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-54', lawId: 'const-santa-fe', number: '54', title: '', text: `La Provincia reconoce la función social de la cooperación en el campo económico, en sus diferentes modalidades. La ley promueve y favorece el cooperativismo con los medios más idóneos y asegura, con oportuna fiscalización, su carácter y finalidades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 53, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-55', lawId: 'const-santa-fe', number: '55', title: '', text: `La Provincia estimula y protege el ahorro popular en todas sus formas y lo orienta hacia la propiedad de la vivienda urbana y del predio para el trabajo rural e inversiones en actividades productivas dentro del territorio de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 54, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-56', lawId: 'const-santa-fe', number: '56', title: '', text: `La Provincia garantiza el pleno ejercicio de los derechos políticos de conformidad con los principios de la democracia representativa. Las personas tienen derecho a participar de los asuntos públicos, directamente o a través de los representantes elegidos en elecciones periódicas mediante sufragio universal, igual y obligatorio. El voto es secreto e intransferible. Son electores las personas que se encuentren inscriptas en el padrón electoral provincial. Los extranjeros son electores en los órdenes provincial y municipal. Ninguna persona puede ser candidata para ocupar cargos electivos si ha sido condenada por delitos dolosos en las condiciones que determine la ley. Una ley aprobada por mayoría absoluta de integrantes de cada Cámara determina la competencia judicial permanente y específica en materia electoral y de partidos políticos, así como los principios y la autoridad encargada de la organización de las elecciones, que debe contemplar: 1) la autoridad única del presidente de la mesa receptora de votos, a cuyas órdenes está la fuerza pública; 2) comienzo y conclusión de la elección dentro del día fijado; 3) escrutinio provisional público, inmediatamente después de cerrado el acto electoral y en la propia mesa, cuyo resultado se consignará en el acta suscripta por el presidente del comicio y fiscales presentes, a quienes el primero dará certificado de dicho resultado; y, 4) prohibición del arresto de electores, salvo en flagrante delito o por orden emanada de autoridad competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 55, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-57', lawId: 'const-santa-fe', number: '57', title: '', text: `Los partidos políticos son instituciones fundamentales para el desarrollo y fortalecimiento del sistema democrático. Expresan el pluralismo político, concurren a la formación y manifestación de la voluntad popular y son un instrumento esencial para la participación política. Ejercen competencia exclusiva para la postulación de candidatos a cargos electivos y deben dar publicidad del origen y destino de sus fondos. Se garantiza su libre creación, funcionamiento democrático y la capacitación de sus dirigentes. Una ley aprobada con mayoría absoluta del total de integrantes de cada Cámara regula el régimen de partidos políticos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 56, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-58', lawId: 'const-santa-fe', number: '58', title: '', text: `La ciudadanía tiene el derecho de participar en la dirección de los asuntos públicos por medio de sus representantes libremente elegidos o de manera directa a través del ejercicio de los mecanismos que establece esta Constitución para la toma de decisiones en la planificación y la gestión de los asuntos públicos. La Provincia garantiza la participación amplia, los derechos políticos y la publicidad en condiciones de igualdad y transparencia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 57, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-59', lawId: 'const-santa-fe', number: '59', title: '', text: `La ciudadanía tiene el derecho de iniciativa popular para la presentación de proyectos de ley. No pueden ser objeto de iniciativa popular los proyectos referidos a reforma constitucional, tratados o convenios, régimen electoral, materia procesal penal, tributaria y presupuestaria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 58, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-60', lawId: 'const-santa-fe', number: '60', title: '', text: `El Poder Legislativo con el voto de la mayoría absoluta de la totalidad de integrantes de cada Cámara puede someter a referéndum la sanción, reforma o derogación de leyes. No pueden ser objeto de referéndum los proyectos de ley o las decisiones referidas a materias excluidas de la iniciativa popular. La ley de convocatoria a referéndum no puede ser vetada. El voto es obligatorio y el resultado vinculante.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 59, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-61', lawId: 'const-santa-fe', number: '61', title: '', text: `El Poder Legislativo y el Poder Ejecutivo pueden convocar a consulta popular sobre asuntos de interés general. El voto en la consulta es optativo y el resultado no es vinculante. No pueden ser objeto de consulta popular los proyectos de ley o las decisiones referidas a materias excluidas de la iniciativa popular.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 60, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-62', lawId: 'const-santa-fe', number: '62', title: '', text: `La ciudadanía tiene derecho a requerir la revocación del mandato de los funcionarios electivos provinciales por grave incumplimiento de sus funciones, después de transcurrido un año desde la iniciación del mandato y antes de los diez meses de su finalización. El procedimiento de revocatoria tramita a pedido de un número de ciudadanos inscriptos en el padrón electoral del distrito no inferior al veinticinco por ciento del total. Si la opción por la revocatoria del mandato obtiene el apoyo de más del cincuenta por ciento de los electores inscriptos en el padrón electoral del distrito correspondiente, el funcionario queda destituido del cargo. Los requisitos y procedimientos de la convocatoria son determinados por una ley sancionada con el voto de los dos tercios de la totalidad de integrantes de cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 61, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-63', lawId: 'const-santa-fe', number: '63', title: '', text: `La Provincia instituye un Consejo de carácter consultivo y asesor del Poder Ejecutivo y del Poder Legislativo que promueve la concertación de acuerdos que faciliten la convivencia de intereses plurales y divergentes y contribuye a la definición de políticas de interés general para la Provincia. El Consejo está integrado por representantes de los sectores del trabajo, la producción y la economía social, las organizaciones sociales, académicas, científicas y profesionales; promueve la participación plural y equitativa con alcance regional. La función no será remunerada. La ley reglamenta su composición, forma de elección, duración de los cargos, atribuciones, organización y funcionamiento, las materias sobre las que dictamina, la forma de adopción de sus decisiones y el carácter de las consultas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 62, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-64', lawId: 'const-santa-fe', number: '64', title: '', text: `La Provincia puede convocar a audiencias públicas con el objeto de informar y debatir sobre asuntos de interés común y de carácter general. La ciudadanía puede solicitar la convocatoria. Se procura la participación de funcionarios públicos responsables de las áreas y materias objeto de debate. La ley reglamenta su procedimiento que debe guiarse por los principios de igualdad, publicidad, oralidad, accesibilidad, gratuidad y de representación territorial. El Poder Legislativo debe convocar a audiencias públicas previas a la aprobación de proyectos de ley en materia ambiental y de servicios públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 63, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-65', lawId: 'const-santa-fe', number: '65', title: '', text: `La Provincia reconoce la existencia de instituciones de gestión social surgidas de la comunidad y legalmente constituidas que tengan por finalidad promover el acceso a derechos o administrar asuntos de interés común que se encuentren habilitadas por el ordenamiento jurídico. La Provincia reconoce la actividad desarrollada por los cuerpos de bomberos voluntarios en todo su territorio. Brinda el apoyo, la colaboración y el respaldo para el cumplimiento de su misión, conforme lo establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 64, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-66', lawId: 'const-santa-fe', number: '66', title: '', text: `El Poder Legislativo de la Provincia es ejercido por la Legislatura, compuesta de dos Cámaras: la Cámara de Senadores y la Cámara de Diputados. Los miembros de ambas Cámaras se reúnen en Asamblea Legislativa solamente en los casos y para los fines previstos por esta Constitución. La asamblea es presidida por el vicegobernador, en su defecto por el presidente provisional del Senado y, a falta de éste, por el presidente de la Cámara de Diputados. Sus decisiones son válidas si está presente la mitad más uno de los legisladores y se adoptan por la mayoría absoluta de los presentes, salvo disposición en contrario de esta Constitución. Dicta el reglamento para el desempeño de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 65, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-67', lawId: 'const-santa-fe', number: '67', title: '', text: `La Cámara de Diputados se compone de cincuenta miembros elegidos directamente por el pueblo mediante sistema de representación proporcional, constituyendo la Provincia un distrito único. Las listas deben incluir por lo menos un candidato con residencia en cada departamento y respetar la paridad de género. Junto con los titulares se eligen diputados suplentes para completar períodos en las vacantes que se produzcan. Para acceder a la distribución de cargos se debe alcanzar el porcentaje mínimo de votos que establece la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 66, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-68', lawId: 'const-santa-fe', number: '68', title: '', text: `Son elegibles para el cargo de diputado los ciudadanos argentinos que tengan por lo menos veintiún años de edad. Si no hubieran nacido en la Provincia, dos años de residencia inmediata y efectiva en esta y, en su caso, dos años de residencia inmediata y efectiva en el departamento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 67, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-69', lawId: 'const-santa-fe', number: '69', title: '', text: `Los diputados duran cuatro años en el ejercicio de sus funciones y son reelegibles una sola vez de manera consecutiva. Si han sido reelectos no pueden ser elegidos nuevamente sino con el intervalo de un período. Su mandato comienza y concluye simultáneamente con el del Poder Ejecutivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 68, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-70', lawId: 'const-santa-fe', number: '70', title: '', text: `La Cámara de Diputados elige anualmente entre sus integrantes su presidente y sus reemplazantes legales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 69, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-71', lawId: 'const-santa-fe', number: '71', title: '', text: `La Cámara de Senadores se compone de un senador por cada departamento de la Provincia, elegido directamente por el pueblo, a simple pluralidad de sufragios. Juntamente con los titulares se eligen senadores suplentes para completar períodos en las vacantes que se produzcan.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 70, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-72', lawId: 'const-santa-fe', number: '72', title: '', text: `Son elegibles para el cargo de senador los ciudadanos argentinos que tengan por lo menos veinticinco años de edad y dos años de residencia inmediata y efectiva en el departamento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 71, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-73', lawId: 'const-santa-fe', number: '73', title: '', text: `Los senadores duran cuatro años en el ejercicio de sus funciones y son reelegibles una sola vez de manera consecutiva. Si han sido reelectos no pueden ser elegidos nuevamente sino con el intervalo de un período. Su mandato comienza y concluye simultáneamente con el del Poder Ejecutivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 72, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-74', lawId: 'const-santa-fe', number: '74', title: '', text: `La Cámara de Senadores es presidida por el vicegobernador y, en caso de ausencia, enfermedad, renuncia, muerte, inhabilidad física o mental sobreviniente de carácter permanente, destitución o suspensión del mismo, o cuando se halle en ejercicio del Poder Ejecutivo, por un presidente provisional que elige anualmente de su seno. El vicegobernador sólo tiene voto en caso de empate.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 73, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-75', lawId: 'const-santa-fe', number: '75', title: '', text: `Ambas Cámaras se reúnen en sesiones ordinarias desde el 15 de febrero hasta el 30 de noviembre de cada año. El Poder Ejecutivo convoca a sesiones extraordinarias cuando lo considere necesario y sólo para tratar los asuntos que determine. Las Cámaras pueden convocarse a sesiones extraordinarias a pedido de la cuarta parte de sus integrantes y por tiempo limitado para tratar graves asuntos de interés público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 74, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-76', lawId: 'const-santa-fe', number: '76', title: '', text: `Ambas Cámaras empiezan y concluyen simultáneamente sus períodos de sesiones, y ninguna de ellas, mientras se hallen reunidas, puede suspender las suyas por más de seis días sin el acuerdo de la otra.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 75, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-77', lawId: 'const-santa-fe', number: '77', title: '', text: `Las decisiones de las Cámaras son válidas si está presente la mitad más uno de sus miembros y son adoptadas por la mayoría de los presentes, salvo los casos en que esta Constitución prescribe mayorías especiales. En estos últimos supuestos se computan los votos de los presidentes que son miembros de los cuerpos. Sin embargo, en minoría pueden acordar las medidas que estimen necesario para obtener el "quórum" requerido, inclusive la compulsión física de los inasistentes en los términos y bajo las sanciones que establezcan los reglamentos; y con no menos de la tercera parte de los miembros de la Cámara, en los días ordinarios de sesión, dar entrada a asuntos, escuchar informes o proseguir deliberaciones anteriores, sin adoptar resoluciones de ninguna naturaleza.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 76, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-78', lawId: 'const-santa-fe', number: '78', title: '', text: `Cada Cámara dicta su reglamento, designa y remueve sus empleados y ejerce la policía de sus locales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 77, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-79', lawId: 'const-santa-fe', number: '79', title: '', text: `Las sesiones de ambas Cámaras son públicas, salvo que acuerden reunirse en sesión secreta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 78, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-80', lawId: 'const-santa-fe', number: '80', title: '', text: `Las Cámaras tienen el derecho de requerir la asistencia a sus sesiones de los ministros del Poder Ejecutivo para suministrar informes o explicaciones sobre puntos que previamente se les fije. Los ministros pueden excusar su asistencia en el primer caso y dar por escrito los informes solicitados, no así en el segundo caso, en que deben concurrir al seno de las Cámaras.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 79, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-81', lawId: 'const-santa-fe', number: '81', title: '', text: `Cada Cámara puede designar comisiones con propósitos de información e investigación sobre materias o asuntos de interés público y proveerlas en cada caso de las facultades necesarias, las que no pueden exceder de los poderes de la autoridad judicial, para el desempeño de sus cometidos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 80, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-82', lawId: 'const-santa-fe', number: '82', title: '', text: `Las Cámaras pueden reprimir con arresto que no exceda de treinta días a toda persona extraña al cuerpo que viole sus privilegios o altere el orden en sus sesiones, sin perjuicio de la responsabilidad penal en que aquélla hubiere incurrido.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 81, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-83', lawId: 'const-santa-fe', number: '83', title: '', text: `Cada Cámara es juez exclusivo de la elección de sus miembros y de la validez de sus títulos y, con el voto de las dos terceras partes de los componentes del cuerpo, resuelve la existencia de causas sobrevinientes de inelegibilidad y de incompatibilidad, sin que, en ambos casos, una vez pronunciada al respecto, pueda volver sobre su decisión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 82, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-84', lawId: 'const-santa-fe', number: '84', title: '', text: `Al recibirse de sus cargos, los legisladores prestan juramento de desempeñarlo conforme a la Constitución y a las leyes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 83, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-85', lawId: 'const-santa-fe', number: '85', title: '', text: `Cada Cámara puede, con el voto de las dos terceras partes de sus miembros, corregir a cualquiera de éstos, y aun excluirlo de su seno, por desorden de conducta en el ejercicio de sus funciones. La inasistencia a la mitad de las sesiones del período ordinario determina la cesación en el mandato, salvo los casos de licencia o suspensión en el cargo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 84, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-86', lawId: 'const-santa-fe', number: '86', title: '', text: `Ningún integrante de ambas Cámaras puede ser acusado, perseguido ni molestado por las opiniones o los votos que emite. Fenecido su mandato ningún legislador puede ser acusado o interrogado judicialmente ni molestado por las opiniones que haya expresado en el ejercicio de sus funciones. Los legisladores no pueden ser arrestados ni restringidos en su libertad personal sin autorización de la Cámara a la que pertenecen, concedida por el voto de dos tercios de los miembros presentes. No se requiere autorización de la Cámara respectiva cuando exista condena penal firme que imponga pena privativa de la libertad por la comisión de delitos dolosos. Si un legislador es sorprendido en el acto de cometer un delito que tenga prevista una pena privativa de la libertad, será aprehendido y se comunicará de inmediato a la Cámara a la que pertenece con sumaria información del hecho. La inmunidad de arresto no implica la de proceso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 85, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-87', lawId: 'const-santa-fe', number: '87', title: '', text: `Es incompatible el cargo de diputado o senador con cualquier otro de carácter nacional, provincial o municipal, sea electivo o no, excepto los cargos docentes y las comisiones honorarias eventuales de la Nación, de la Provincia o de los municipios, que solamente pueden ser aceptadas con autorización de la Cámara correspondiente, o si ésta estuviere en receso, con obligación de dar cuenta a ella en su oportunidad. Los agentes de la Administración pública provincial o municipal que resultaren elegidos diputados o senadores quedan automáticamente con licencia, sin goce de sueldo, por todo el tiempo que dure el mandato. También es incompatible el cargo de legislador con la propiedad personal, individual o asociada, de empresas que gestionen servicios por cuenta de la Provincia o entidades públicas menores, o sean subsidiadas por éstas, y con el desempeño de funciones de dirección, administración, asesoramiento, representación o asistencia profesional en empresas ajenas en iguales condiciones. El legislador que haya aceptado algún cargo incompatible con el suyo, que da por ese solo hecho separado de éste.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 86, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-88', lawId: 'const-santa-fe', number: '88', title: '', text: `Los legisladores reciben por sus servicios la retribución que determine la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 87, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-89', lawId: 'const-santa-fe', number: '89', title: '', text: `Corresponde a la Asamblea Legislativa: 1) recibir el juramento del gobernador y del vicegobernador; 2) resolver en caso de empate en la elección de los mismos; 3) decidir sobre las renuncias de dichos funcionarios y declarar su inhabilidad física o mental sobreviniente de carácter permanente, en ambos casos por el voto de los dos tercios de la totalidad de los legisladores; 4) escuchar el informe anual del gobernador sobre el estado de los negocios públicos, en ocasión de abrirse el período de sesiones ordinarias de las Cámaras; y, 5) prestar el acuerdo requerido por esta Constitución o las leyes para la designación de magistrados, fiscales, defensores o funcionarios, el que se entiende prestado si no se expidiera dentro del término de cuarenta y cinco días de convocada al efecto la Asamblea. La convocatoria debe realizarse dentro del quinto día de recibido el pedido de acuerdo o, en caso de remitir la solicitud en el receso legislativo, de abierto el período ordinario de sesiones. En los casos de los integrantes de la Corte Suprema de Justicia, el fiscal general y el defensor general el acuerdo debe prestarse de manera expresa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 88, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-90', lawId: 'const-santa-fe', number: '90', title: '', text: `Corresponde a la Legislatura: 1) establecer la división política de la Provincia, que no puede alterarse sin el voto de las dos terceras partes de integrantes de cada Cámara y las divisiones convenientes para su mejor administración; 2) legislar en materia electoral y régimen de los partidos políticos por mayoría absoluta de la totalidad de integrantes de cada Cámara; 3) legislar en materia de organización y procedimientos judiciales; 4) legislar en materia de organización de la Administración Pública y el estatuto de agentes públicos, que incluya, entre otras, garantías de ingreso, estabilidad, carrera e indemnización por cesantía injustificada; 5) legislar en materia de régimen municipal, áreas metropolitanas y regiones, según las bases establecidas por la Constitución Nacional y por esta Constitución; 6) crear los tributos conforme el artículo 8; 7) fijar anualmente el presupuesto de gastos y cálculo de recursos. En el primero deben figurar todos los gastos ordinarios y extraordinarios de la Provincia, aun los autorizados por leyes especiales, las que se tendrán por derogadas si no se incluyen en el presupuesto las partidas para su ejecución. La Legislatura no puede aumentar los sueldos y gastos proyectados por el Poder Ejecutivo, salvo para la ejecución de las leyes especiales, en cuanto no excedan el cálculo de recursos. No sancionado en tiempo un presupuesto, seguirá en vigencia el anterior en sus partidas ordinarias, hasta la sanción del nuevo; 8) aprobar o desechar anualmente la cuenta de inversión; 9) arreglar el pago de la deuda interna y externa de la Provincia; 10) aprobar o desechar los convenios celebrados con la Nación, con otras Provincias, con la Ciudad Autónoma de Buenos Aires, con otros Estados, entes públicos o privados extranjeros y organismos internacionales, en el marco de sus competencias; 11) autorizar al Poder Ejecutivo para celebrar contratos de concesión de servicios públicos, empréstitos y operaciones de crédito, en este caso, no puede comprometer más de la cuarta parte de la renta provincial; 12) autorizar al Poder Ejecutivo a celebrar contratos que tengan por objeto actividades de juegos de azar y apuestas en cualquiera de sus modalidades; 13) promover el desarrollo de bancos públicos como instrumentos de política financiera y de prestación de servicios, que estimulen el crédito hacia la producción y la generación de empleo; 14) legislar sobre tierras fiscales; 15) declarar de interés general la expropiación de bienes por leyes generales o especiales; 16) conceder estímulos por tiempo determinado con fines de promoción de la actividad económica y atención de situaciones sociales; 17) legislar en materia rural, fiscal, de protección del ambiente, ordenamiento territorial, convivencia, seguridad alimentaria, derechos de consumidores y usuarios, educación, salud, deporte y seguridad social, sin perjuicio de las competencias que en estas materias le puedan corresponder a los municipios; 18) acordar amnistías por delitos o infracciones en general de jurisdicción provincial; 19) conceder subsidios; 20) legislar en materia de participación ciudadana; 21) fijar su presupuesto de gastos; 22) convocar a elecciones provinciales si el Poder Ejecutivo no lo hiciese con la anticipación legal, a cuyo fin puede, en su caso, convocarse a sesiones extraordinarias por acuerdo propio y a solicitud de una cuarta parte de la totalidad de integrantes de cada Cámara; 23) autorizar al gobernador o vicegobernador para ausentarse del país; 24) recibir durante el mes de abril de cada año el informe de gestión y la respectiva rendición de cuentas del fiscal general, defensor general y presidente del Tribunal de Cuentas y cualquier otro órgano que tenga esta obligación según se establezca por ley; 25) promover medidas de acción positiva; 26) proveer al desarrollo integral de la Provincia, promoviendo el bienestar general, la inclusión social, el crecimiento económico y el desarrollo productivo, científico y tecnológico, mediante el impulso de la industria, el comercio, el turismo, el asociativismo, el mutualismo, el cooperativismo y la infraestructura estratégica que incluya a los puertos y a los sistemas de transporte; 27) promover el desarrollo integral de la industria a través del fortalecimiento de las cadenas de valor, la competitividad y la innovación, el acceso a la tecnología, al crédito, la capacitación, los incentivos tributarios y la diversificación del entramado industrial; y, 28) en general, ejercer la potestad legislativa en cuanto se considere necesario o conveniente para la organización y funcionamiento de los poderes públicos y para la consecución de los fines de esta Constitución, en ejercicio de los poderes no delegados al gobierno federal, sin otras limitaciones que las emergentes de esta Constitución o de la Nacional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 89, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-91', lawId: 'const-santa-fe', number: '91', title: '', text: `Las leyes pueden tener origen en cualquiera de las Cámaras por proyectos presentados por sus integrantes, por el Poder Ejecutivo o por iniciativa popular.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 90, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-92', lawId: 'const-santa-fe', number: '92', title: '', text: `Aprobado un proyecto por la Cámara de origen, se remite para su consideración a la otra Cámara y, si ésta también lo aprueba, pasa al Poder Ejecutivo. Si el Poder Ejecutivo está conforme, lo promulga como ley de la Provincia y dispone su publicación inmediata. Queda convertido en ley todo proyecto sancionado por ambas Cámaras si, comunicado al Poder Ejecutivo, éste no lo devuelve observado dentro del plazo de diez días hábiles.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 91, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-93', lawId: 'const-santa-fe', number: '93', title: '', text: `Ningún proyecto de ley desechado totalmente por una de las Cámaras podrá repetirse en las sesiones del mismo año. Ninguna de las Cámaras puede desechar totalmente un proyecto que hubiera tenido origen en ella y luego hubiese sido adicionado o enmendado por la Cámara revisora. Si el proyecto fuere objeto de adiciones o correcciones por la Cámara revisora, deberá indicarse el resultado de la votación a fin de establecer si tales adiciones o correcciones fueron realizadas por mayoría absoluta de los presentes o por las dos terceras partes de los presentes. La Cámara de origen podrá por mayoría absoluta de los presentes aprobar el proyecto con las adiciones o correcciones introducidas o insistir en la redacción originaria, a menos que las adiciones o correcciones las haya realizado la revisora por dos terceras partes de los presentes. En este último caso, el proyecto pasará al Poder Ejecutivo con las adiciones o correcciones de la Cámara revisora, salvo que la Cámara de origen insista en su redacción originaria con el voto de las dos terceras partes de los presentes. La Cámara de origen no podrá introducir nuevas adiciones o correcciones a las realizadas por la Cámara revisora.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 92, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-94', lawId: 'const-santa-fe', number: '94', title: '', text: `Vetado en todo o en parte un proyecto por el Poder Ejecutivo, vuelve con sus observaciones a la Cámara de origen, la que, si en votación nominal lo confirma por mayoría de dos tercios de los votos presentes, lo remite a la Cámara revisora, y si ésta también se expide de igual manera, el proyecto queda convertido en ley y se comunica al Poder Ejecutivo para su promulgación. Si ambas Cámaras no insisten con dicha mayoría, el proyecto no puede repetirse en las sesiones del año. Si el veto ha sido parcial y las Cámaras aprueban por simple mayoría las enmiendas propuestas por el Poder Ejecutivo, el proyecto, con éstas, queda convertido en ley. La Legislatura debe pronunciarse sobre el veto del Poder Ejecutivo dentro del término de un mes de comunicado, o, en su caso, de iniciado el período ordinario de sesiones; en su defecto, se considera rechazado el proyecto. El veto parcial de la ley de presupuesto no implica la necesidad de devolverlo totalmente a la Legislatura y puede promulgarse en las partes no observadas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 93, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-95', lawId: 'const-santa-fe', number: '95', title: '', text: `Las leyes son obligatorias luego de su publicación. El Poder Ejecutivo debe publicarlas dentro de los ocho días de promulgadas y, en su defecto, dispone la publicación el presidente de la Cámara que hubiere prestado la sanción definitiva. Las leyes entran en vigor el noveno día siguiente al de su publicación, salvo que las mismas leyes establezcan otras fechas al efecto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 94, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-96', lawId: 'const-santa-fe', number: '96', title: '', text: `Los proyectos de ley caducan si no reciben sanción definitiva dentro de dos períodos ordinarios consecutivos desde su presentación, incluyendo el de ingreso. Una vez caducados solo podrán volver a presentarse como nuevos proyectos. La caducidad de un proyecto no afecta la vigencia de otros que hayan sido tratados en conjunto con él, salvo que se disponga lo contrario mediante resolución expresa de la Cámara respectiva.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 95, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-97', lawId: 'const-santa-fe', number: '97', title: '', text: `El Poder Ejecutivo es ejercido por un ciudadano con el título de gobernador de la Provincia y, en su defecto, por un vicegobernador, elegido al mismo tiempo, en igual forma y por idéntico período que el gobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 96, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-98', lawId: 'const-santa-fe', number: '98', title: '', text: `Para ser elegido gobernador o vicegobernador se requiere ser ciudadano argentino nativo o hijo de ciudadano nativo si hubiere nacido en país extranjero y tener, por lo menos, treinta años de edad y dos años de residencia inmediata en la Provincia sino hubiere nacido en ésta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 97, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-99', lawId: 'const-santa-fe', number: '99', title: '', text: `El gobernador y vicegobernador duran cuatro años en el ejercicio de sus funciones y pueden ser reelegidos o sucederse recíprocamente por un período consecutivo. Si han sido reelegidos o se han sucedido recíprocamente no pueden ser elegidos nuevamente para ninguno de esos cargos sin el intervalo de un período.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 98, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-100', lawId: 'const-santa-fe', number: '100', title: '', text: `Al tomar posesión de sus cargos el gobernador y el vicegobernador prestan juramento de desempeñarlo conforme a la Constitución y a las leyes, ante el presidente de la Asamblea Legislativa, en sesión especial de ésta, o, en su defecto, ante el presidente de la Corte Suprema de Justicia, reunido este cuerpo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 99, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-101', lawId: 'const-santa-fe', number: '101', title: '', text: `El vicegobernador reemplaza al gobernador en caso de muerte, destitución, renuncia o inhabilidad física o mental sobreviniente de éste, por el resto del período legal; y en caso de enfermedad, ausencia o suspensión en tanto el impedimento no cese.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 100, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-102', lawId: 'const-santa-fe', number: '102', title: '', text: `En caso de muerte, destitución, renuncia o inhabilidad física o mental sobreviniente del vicegobernador en ejercicio del Poder Ejecutivo, lo sustituye el presidente provisional del Senado mientras se procede a nueva elección, la que no puede recaer en este último, para completar período. La convocatoria debe hacerse dentro del plazo de diez días y la elección realizarse en término no mayor de noventa días. No procede nueva elección si el resto del período no excede de un año y medio. El vicegobernador en ejercicio es igualmente reemplazado por el presidente provisional del Senado en caso de enfermedad, ausencia o suspensión, mientras no cese el impedimento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 101, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-103', lawId: 'const-santa-fe', number: '103', title: '', text: `El gobernador y vicegobernador en desempeño del Poder Ejecutivo residen en la capital de la Provincia, pero pueden permanecer fuera de ella, dentro del territorio provincial, en ejercicio de sus funciones, por un término que, en cada caso, no exceda de treinta días. No pueden ausentarse del territorio de la Provincia, por un plazo mayor de diez días, sin la autorización de la Legislatura; ni, en todo caso, del territorio de la República sin esa autorización. En el receso de las Cámaras, y siendo necesario el permiso previo pueden ausentarse sólo por un motivo urgente de interés público y por el tiempo indispensable, comunicando a aquéllas oportunamente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 102, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-104', lawId: 'const-santa-fe', number: '104', title: '', text: `El gobernador y vicegobernador reciben por sus servicios la retribución que fije la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 103, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-105', lawId: 'const-santa-fe', number: '105', title: '', text: `El gobernador y vicegobernador son elegidos directamente por el pueblo de la Provincia, a simple pluralidad de sufragios. La elección debe realizarse con una antelación no mayor de seis meses ni menor de tres. En caso de empate, decide, en una sola sesión y sin debate, por mayoría absoluta de los miembros presentes, la Asamblea Legislativa surgida de la misma elección.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 104, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-106', lawId: 'const-santa-fe', number: '106', title: '', text: `Si antes de ocupar el cargo muriere o renunciare el ciudadano electo gobernador, lo reemplaza el vicegobernador conjuntamente elegido.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 105, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-107', lawId: 'const-santa-fe', number: '107', title: '', text: `El gobernador de la Provincia tiene a su cargo las siguientes atribuciones y deberes: 1) es el jefe de la Administración Pública; 2) representa a la Provincia, es el responsable de la administración, ejecuta las leyes, dirige la planificación, aplicación y evaluación de las políticas públicas; 3) celebra convenios con otras provincias, con la Ciudad Autónoma de Buenos Aires, con municipios, con entes públicos de otras jurisdicciones y con la Nación, con el objeto de fijar políticas comunes de integración y desarrollo regional y de administración de justicia, con aprobación de la Legislatura y del Congreso de la Nación, según corresponda; y convenios internacionales para la gestión de intereses de la Provincia, con la aprobación de la Legislatura, en tanto no afecten las facultades delegadas al gobierno federal; 4) concurre a la formación de las leyes con las facultades emergentes de esta Constitución, las promulga y publica; 5) expide reglamentos de ejecución y autónomos de acuerdo con lo previsto por esta Constitución y las leyes; 6) provee a la organización, prestación y control de los servicios públicos, orientados a la eficiencia en las prestaciones, la universalidad de su acceso y el rol de estos en el entramado productivo; 7) celebra contratos; 8) organiza la Administración Pública para satisfacer las necesidades de la comunidad con eficacia, eficiencia, economicidad y oportunidad y promueve su mejora continua con el propósito de optimizar su organización y funcionamiento; 9) nombra y remueve a ministros y agentes de la Administración Pública de acuerdo con las previsiones de esta Constitución y las leyes, siempre que el nombramiento o remoción no competa a otra autoridad; 10) puede asignar al vicegobernador tareas determinadas y concretas dentro del ámbito de la administración y por un plazo determinado, sin que implique delegación de funciones; 11) presenta a la Legislatura antes del treinta y uno de octubre de cada año, el proyecto de presupuesto general de gastos y cálculo de recursos de la Provincia y de las entidades autárquicas; 12) presenta anualmente a la Legislatura la cuenta de inversión del ejercicio anterior; 13) recauda y dispone la inversión de los recursos de la Provincia con arreglo a las leyes respectivas; 14) informa a la Legislatura, al abrirse las sesiones ordinarias, sobre el estado general de la administración; 15) convoca a sesiones extraordinarias de la Legislatura de conformidad con esta Constitución; 16) efectúa las convocatorias a elecciones en los casos y oportunidades legales; 17) convoca a las iniciativas institucionales de participación ciudadana en los casos previstos en esta Constitución y las leyes; 18) puede indultar o conmutar penas por delitos sujetos a la jurisdicción provincial, previo informe de la Corte Suprema de Justicia, excepto delitos contra la administración pública; 19) diseña, planifica y ejecuta políticas públicas orientadas al desarrollo integral de la Provincia, promoviendo el bienestar general, la inclusión social, el crecimiento económico y el desarrollo productivo, científico y tecnológico, mediante el impulso de la industria y su acceso a mercados, el turismo, el asociativismo, el mutualismo, el cooperativismo y la infraestructura estratégica que incluya a los puertos y los sistemas de transporte; 20) diseña, planifica y ejecuta la política de seguridad provincial y la política criminal, en coordinación con los otros poderes provinciales y municipales y con las autoridades competentes en la persecución penal de los delitos; 21) presta el auxilio de las fuerzas de seguridad a todos los órganos, entes y autoridades provinciales y municipales, conforme a la ley; 22) designa un ministro con competencias para articular las relaciones con los otros poderes del Estado, en caso de que así la ley de ministerios lo contemple, cuya designación requerirá acuerdo legislativo y su remoción será atribución del gobernador; 23) conoce y resuelve los recursos e instancias administrativas que establezca la ley; y, 24) hace cumplir, en su carácter de agente natural del gobierno federal, la Constitución y las leyes de la Nación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 106, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-108', lawId: 'const-santa-fe', number: '108', title: '', text: `El despacho de los asuntos que incumben al Poder Ejecutivo está a cargo de ministros designados por el gobernador, en el número y con las funciones, en los respectivos ramos, que determine una ley especial. Al recibirse de sus cargos prestan juramento ante el gobernador de desempeñarlos conforme a la Constitución y a las leyes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 107, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-109', lawId: 'const-santa-fe', number: '109', title: '', text: `Para ser ministro se requieren las mismas calidades que para ser diputado y le comprenden las mismas incompatibilidades de los legisladores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 108, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-110', lawId: 'const-santa-fe', number: '110', title: '', text: `Los ministros refrendan con su firma las resoluciones del gobernador, sin la cual éstas carecen de eficacia. Sólo pueden resolver por sí mismos en lo concerniente al régimen administrativo interno de sus respectivos departamentos y dictar providencias de trámite.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 109, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-111', lawId: 'const-santa-fe', number: '111', title: '', text: `Sin perjuicio de las facultades de las Cámaras a su respecto, los ministros tienen el derecho de concurrir a las sesiones de aquéllas y participar en sus deliberaciones, pero no votar. Dentro de los treinta días posteriores a la apertura de las sesiones ordinarias de la Legislatura, los ministros deben presentar a ésta una memoria detallada del estado de la administración de los asuntos de sus respectivos ministerios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 110, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-112', lawId: 'const-santa-fe', number: '112', title: '', text: `Los ministros son responsables de las resoluciones que autoricen y solidariamente de las que refrenden conjuntamente con sus colegas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 111, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-113', lawId: 'const-santa-fe', number: '113', title: '', text: `Los ministros pueden ser removidos de sus cargos por el gobernador, que también decide sus renuncias, y ser sometidos a juicio político.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 112, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-114', lawId: 'const-santa-fe', number: '114', title: '', text: `En los casos de vacancia o de cualquier impedimento de un ministro, los actos del gobernador pueden ser refrendados por algunos de sus colegas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 113, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-115', lawId: 'const-santa-fe', number: '115', title: '', text: `Los ministros reciben por sus servicios la retribución que fije la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 114, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-116', lawId: 'const-santa-fe', number: '116', title: '', text: `El Fiscal de Estado es el asesor legal del Poder Ejecutivo, tiene a su cargo la defensa de los intereses de la Provincia ante los tribunales de justicia en los casos y en la forma que establecen la Constitución o las leyes, y desempeña las demás funciones que éstas le encomiendan. El Fiscal de Estado es designado por el Poder Ejecutivo con acuerdo de la Asamblea Legislativa, debe reunir las condiciones requeridas para ser miembro de la Corte Suprema de Justicia y tiene las mismas incompatibilidades y prohibiciones que los miembros del Poder Judicial. El Fiscal de Estado ejerce sus funciones durante el período del gobernador que lo ha designado, sin perjuicio de ser renombrado, es inamovible y puede ser removido sólo según las normas del juicio político.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 115, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-117', lawId: 'const-santa-fe', number: '117', title: '', text: `El Poder Judicial de la Provincia es ejercido, exclusivamente, por una Corte Suprema de Justicia, cámaras de apelación, jueces de primera instancia y demás tribunales y jueces que establezca la ley. Sin embargo, la ley puede instituir tribunales colegiados de instancia única.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 116, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-118', lawId: 'const-santa-fe', number: '118', title: '', text: `La Corte Suprema de Justicia se compone de siete ministros. Su integración procura la paridad de género y la representación territorial. Los jueces de revisión y los demás jueces pueden ser organizados en Colegios de Jueces.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 117, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-119', lawId: 'const-santa-fe', number: '119', title: '', text: `La Procuración General integra el Poder Judicial y tiene por función la defensa de la legalidad y de los intereses generales de la sociedad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 118, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-120', lawId: 'const-santa-fe', number: '120', title: '', text: `Para ser miembro de la Corte Suprema de Justicia, vocal o fiscal de las cámaras de apelación se requiere ser ciudadano argentino, poseer título de abogado y tener, por lo menos, treinta años de edad, diez de ejercicio de la profesión de abogado o de la magistratura y dos años de residencia inmediata en la Provincia si no hubiere nacido en ésta. Para ser juez de primera instancia se requiere ser ciudadano argentino, poseer título de abogado y tener, por lo menos veinticinco años de edad, cuatro de ejercicio de la profesión o de la función judicial como magistrado o funcionario y dos años de residencia inmediata en la Provincia si no hubiere nacido en ésta. La ley fija las condiciones exigidas para los jueces creados por ella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 119, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-121', lawId: 'const-santa-fe', number: '121', title: '', text: `Los ministros de la Corte Suprema de Justicia se designan por el Poder Ejecutivo con acuerdo de la Asamblea Legislativa. Los demás jueces se designan conforme a lo dispuesto en el título quinto de esta parte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 120, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-122', lawId: 'const-santa-fe', number: '122', title: '', text: `El procurador general se designa por el Poder Ejecutivo, con acuerdo de la Asamblea Legislativa. Debe reunir las condiciones previstas para los ministros de la Corte Suprema de Justicia y poseer conocimientos específicos para el ejercicio del cargo. Dura cinco años en sus funciones y puede ser nuevamente designado por un período consecutivo. Percibe una retribución equivalente a la de los ministros de la Corte Suprema de Justicia. Los demás procuradores se designan conforme a lo dispuesto en título quinto de esta parte. Deben reunir las condiciones previstas en el artículo 120.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 121, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-123', lawId: 'const-santa-fe', number: '123', title: '', text: `Los magistrados y funcionarios de la administración de justicia prestan juramento, al asumir sus cargos, de desempeñarlos conforme a la Constitución y a las leyes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 122, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-124', lawId: 'const-santa-fe', number: '124', title: '', text: `Los ministros de la Corte Suprema de Justicia, el procurador general, los jueces y los demás procuradores son inamovibles mientras conserven su idoneidad física, intelectual y ética y el buen desempeño de sus funciones. Cesan de pleno derecho en sus cargos al cumplir setenta y cinco años de edad. No pueden ser ascendidos ni trasladados sin su consentimiento previo. Perciben por sus servicios una retribución que no puede ser suspendida ni disminuida sino por leyes de carácter general y transitorio, extensivas a todos los poderes del Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 123, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-125', lawId: 'const-santa-fe', number: '125', title: '', text: `Los miembros del Poder Judicial no pueden actuar de manera alguna en política. Los magistrados y funcionarios no pueden ejercer profesión o empleo alguno, salvo la docencia en materia jurídica, las comisiones de carácter honorario, técnico y transitorio que les encomienden la Nación, la Provincia o los municipios, y la defensa en juicio de derechos propios, de su cónyuge o de sus hijos menores. La ley determina las incompatibilidades de los empleados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 124, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-126', lawId: 'const-santa-fe', number: '126', title: '', text: `Los magistrados, funcionarios y empleados de la administración de justicia deben residir en el lugar donde desempeñan sus funciones, excepto los ministros de la Corte Suprema de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 125, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-127', lawId: 'const-santa-fe', number: '127', title: '', text: `Los ministros de la Corte Suprema de Justicia están sujetos a juicio político. El procurador general es removido por la Asamblea Legislativa por el voto de la mayoría absoluta de sus miembros por las causales de mal desempeño de sus funciones o comisión de delito doloso. El procedimiento es acusatorio, público y garantiza el derecho de defensa. Los demás jueces y procuradores son enjuiciables conforme a lo dispuesto en el título quinto de esta parte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 126, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-128', lawId: 'const-santa-fe', number: '128', title: '', text: `La Corte Suprema de Justicia: 1) representa al Poder Judicial de la Provincia; 2) ejerce la superintendencia general de la administración de justicia, que puede parcialmente delegar, de acuerdo con la ley, y la consiguiente potestad disciplinaria; 3) dicta los reglamentos y disposiciones que conduzcan al mejor desempeño de la función judicial; 4) dispone, según normas propias, de las partidas para inversiones y gastos de funcionamiento asignadas al Poder Judicial por la ley de presupuesto, sin perjuicio de rendir cuentas; 5) designa, previo concurso, a los funcionarios y empleados del Poder Judicial y los remueve conforme a la ley; 6) envía a los poderes legislativos y ejecutivo un informe anual sobre el estado de la administración de justicia; 7) propone en cualquier tiempo reformas de organización o procedimiento encaminadas a mejorar la administración de justicia; y 8) ejerce las demás funciones que le encomiende la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 127, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-129', lawId: 'const-santa-fe', number: '129', title: '', text: `Compete exclusivamente a la Corte Suprema de Justicia el conocimiento y resolución de: 1) los recursos de inconstitucionalidad que se deduzcan contra las decisiones definitivas de los jueces inferiores sobre materias regidas por esta Constitución; 2) los recursos de revisión de sentencias dictadas en procesos penales en los casos autorizados por la ley; 3) los conflictos de competencia que se susciten entre jueces de la Provincia que no tengan un superior común; 4) los incidentes de recusación de sus propios ministros; 5) los conflictos entre poderes y los que se susciten con el Ministerio Público; 6) los conflictos que se susciten entre la Provincia y un municipio, entre municipios, o entre los órganos de un mismo municipio; y, 7) los juicios de responsabilidad civil contra los jueces.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 128, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-130', lawId: 'const-santa-fe', number: '130', title: '', text: `Los demás tribunales y jueces ejercen la jurisdicción contenciosa y voluntaria, que corresponda a la Provincia, con las competencias que establezca la ley. Asimismo, las funciones de otra índole que ésta les encomiende.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 129, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-131', lawId: 'const-santa-fe', number: '131', title: '', text: `Las sentencias y autos interlocutorios deben tener motivación suficiente, so pena de nulidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 130, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-132', lawId: 'const-santa-fe', number: '132', title: '', text: `Los tribunales y jueces tienen la obligación de fallar las causas dentro de los plazos legales y el retardo reiterado no justificado importa mal desempeño a los efectos de la remoción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 131, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-133', lawId: 'const-santa-fe', number: '133', title: '', text: `La administración de justicia se rige por una ley reglamentaria de su organización y por códigos que determinen sus modos de proceder.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 132, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-134', lawId: 'const-santa-fe', number: '134', title: '', text: `El Ministerio Público es un órgano independiente de los poderes del Estado con autonomía funcional y administrativa y autarquía financiera. Se compone del Ministerio Público de la Acusación y del Ministerio Público de la Defensa, independientes entre sí, dirigidos por un fiscal general y un defensor general respectivamente. El Ministerio Público de la Acusación tiene a su cargo el diseño, la planificación y la ejecución de la política de persecución penal, en coordinación con las demás autoridades de la Provincia. Ejerce la acción penal pública y su actuación se orienta al resguardo de los intereses de las víctimas. El Ministerio Público de la Defensa tiene a su cargo la protección y defensa de los derechos humanos. Tiene por función garantizar el acceso a la justicia, el derecho de defensa efectiva y eficaz, la asistencia jurídica integral de quienes se encuentren en situación de vulnerabilidad o no cuenten con la posibilidad de hacerlo por sus propios medios, tanto en casos individuales como colectivos. La ley determina la organización y el funcionamiento del órgano.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 133, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-135', lawId: 'const-santa-fe', number: '135', title: '', text: `El fiscal general y el defensor general son designados por el Poder Ejecutivo con acuerdo de la Asamblea Legislativa. Deben reunir las condiciones para ser ministro de la Corte Suprema de Justicia y poseer conocimientos específicos para el ejercicio de sus funciones. Duran cinco años en el cargo si conservan su idoneidad física, intelectual y ética y el buen desempeño de sus funciones. Pueden ser nuevamente designados por un solo período consecutivo. Cesan de pleno derecho en sus cargos al cumplir setenta y cinco años de edad. Perciben la misma retribución que los ministros de la Corte Suprema de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 134, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-136', lawId: 'const-santa-fe', number: '136', title: '', text: `El fiscal general y el defensor general son removidos por la Asamblea Legislativa por el voto de la mayoría absoluta de sus miembros, por las causales de mal desempeño de sus funciones o comisión de delito doloso. El procedimiento es acusatorio y público y garantiza el derecho de defensa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 135, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-137', lawId: 'const-santa-fe', number: '137', title: '', text: `Los fiscales y defensores gozan de inamovilidad mientras conserven su idoneidad física, intelectual y ética y el buen desempeño de sus funciones. Cesan de pleno derecho en sus cargos a los setenta y cinco años de edad. Perciben por sus servicios una retribución equiparable a la de los miembros del Poder Judicial, que no puede ser suspendida ni disminuida sino por leyes de carácter general y transitorio, extensivas a todos los poderes del Estado. Para su designación y destitución se procede conforme a lo establecido en el título quinto de esta parte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 136, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-138', lawId: 'const-santa-fe', number: '138', title: '', text: `El fiscal general, el defensor general, los fiscales y los defensores del Ministerio Público tienen las incompatibilidades y garantías funcionales previstas para los funcionarios del Poder Judicial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 137, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-139', lawId: 'const-santa-fe', number: '139', title: '', text: `Los jueces y procuradores del Poder Judicial, los fiscales y defensores del Ministerio Público se designan por el Poder Ejecutivo con acuerdo de la Asamblea Legislativa. La designación requiere la intervención previa del Consejo de Selección del Poder Judicial y del Ministerio Público, cuya función es organizar un procedimiento de selección transparente, público y con participación ciudadana, orientado a garantizar la idoneidad técnica, ética y funcional y la acreditación de los conocimientos, las competencias para el desempeño del cargo y el compromiso democrático de sus postulantes. El Poder Ejecutivo solicita al Consejo de Selección del Poder Judicial y del Ministerio Público la elevación de una propuesta vinculante que resulta de la apertura de un procedimiento de selección cuando no haya listas vigentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 138, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-140', lawId: 'const-santa-fe', number: '140', title: '', text: `El Consejo de Selección del Poder Judicial y del Ministerio Público es un órgano técnico en el ámbito del Poder Ejecutivo y tiene las siguientes competencias: 1) supervisar las diferentes instancias del procedimiento de selección, que debe incluir un concurso público de antecedentes y oposición; 2) convocar a los jurados evaluadores según la especialidad del cargo a cubrir; 3) ponderar el mérito de los postulantes; 4) confeccionar las listas para ser utilizadas en la cobertura de las vacantes; y, 5) elevar al Poder Ejecutivo una propuesta vinculante con los candidatos seleccionados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 139, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-141', lawId: 'const-santa-fe', number: '141', title: '', text: `El Consejo de Selección del Poder Judicial y del Ministerio Público está integrado por: 1) un juez, fiscal o defensor, según corresponda a la vacante a cubrir; 2) un diputado y un senador; 3) un abogado matriculado en los colegios con asiento en la Provincia; y, 4) un profesor por concurso perteneciente a las facultades de derecho de las universidades con sede en la Provincia. Sus integrantes no perciben retribución por su tarea. La ley regula su organización y funcionamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 140, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-142', lawId: 'const-santa-fe', number: '142', title: '', text: `Los jueces y procuradores del Poder Judicial y los fiscales y defensores del Ministerio Público son enjuiciables, por la comisión de faltas graves o de delitos dolosos ante un Jurado de Enjuiciamiento. Está compuesto por: 1) un ministro de la Corte Suprema de Justicia, el fiscal general o el defensor general, según el órgano al que pertenece el acusado, quien lo preside; 2) dos jueces, fiscales o defensores, según corresponda; 3) tres senadores y tres diputados elegidos por sus respectivas Cámaras con representación de la minoría; y, 4) dos abogados matriculados en los colegios con asiento en la Provincia. Sus integrantes no perciben retribución por su tarea. La ley regula su organización y funcionamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 141, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-143', lawId: 'const-santa-fe', number: '143', title: '', text: `El procedimiento ante el Jurado de Enjuiciamiento es acusatorio, oral y público y garantiza el debido proceso. La resolución recaída debe ser fundada. La acusación ante el Jurado de Enjuiciamiento debe ser técnica. La ley dispone el órgano que actúa como acusador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 142, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-144', lawId: 'const-santa-fe', number: '144', title: '', text: `Un Tribunal de Cuentas, con jurisdicción en toda la Provincia, tiene a su cargo, en los casos y en la forma que señale la ley, aprobar o desaprobar la percepción e inversión de caudales públicos y declarar las responsabilidades que resulten. Los miembros del Tribunal de Cuentas duran seis años en sus funciones, son nombrados por el Poder Ejecutivo con acuerdo de la Asamblea Legislativa y pueden ser removidos según las normas del juicio político. Los fallos del Tribunal de Cuentas son susceptibles de los recursos que la ley establezca y las acciones a que dieren lugar deducidas por el Fiscal de Estado. El contralor jurisdiccional administrativo se entenderá sin perjuicio de la atribución de otros órganos de examinar la cuenta de inversión, que contarán previamente con los juicios del Tribunal de Cuentas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 143, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-145', lawId: 'const-santa-fe', number: '145', title: '', text: `La Defensoría del Pueblo es un órgano que tiene como misión principal la promoción, protección y defensa de los derechos e intereses de los individuos y de la comunidad frente a los actos, hechos y omisiones de la Administración Pública y prestadores de servicios públicos. Está a cargo de un defensor del pueblo. Su designación y remoción, así como los alcances de sus funciones y su legitimación procesal son establecidos por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 144, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-146', lawId: 'const-santa-fe', number: '146', title: '', text: `Pueden ser sometidos a juicio político el gobernador, el vicegobernador y sus sustitutos legales en ejercicio del Poder Ejecutivo, sus ministros, el fiscal de Estado, los integrantes de la Corte Suprema de Justicia, los del Tribunal de Cuentas y todo aquel funcionario cuya designación requiera acuerdo legislativo siempre que no tenga previsto otro procedimiento de remoción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 145, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-147', lawId: 'const-santa-fe', number: '147', title: '', text: `A la Cámara de Diputados compete, a petición escrita y fundada de alguno de sus miembros o de cualquier habitante de la Provincia, la facultad de acusar ante el Senado a los funcionarios anteriormente mencionados por mal desempeño de sus funciones, delito cometido en el ejercicio de éstas o crímenes comunes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 146, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-148', lawId: 'const-santa-fe', number: '148', title: '', text: `La acusación no se hará sin previa averiguación de la verdad de los hechos por la comisión permanente respectiva, con citación y audiencia del acusado, y declaración de haber lugar a la formación de causa por las dos terceras partes de los miembros presentes de la Cámara. Si la comisión o, en su caso, la Cámara no se expidiese en el término de noventa días útiles correspondientes a los períodos ordinarios de sesiones o de prórroga, caducarán las actuaciones respectivas, inclusive la petición. Admitida la acusación, la Cámara designará una Comisión para que sostenga la acusación ante el Senado y podrá suspender al funcionario acusado por las dos terceras partes de sus miembros presentes. Si se desechara una petición de acusación manifiestamente temeraria, se aplicará al particular peticionante la sanción de multa o arresto que establezca la reglamentación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 147, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-149', lawId: 'const-santa-fe', number: '149', title: '', text: `Corresponde a la Cámara de Senadores juzgar a los acusados por la Cámara de Diputados, a cuyo fin aquélla se constituye en tribunal, dentro del plazo que señale la ley, previo juramento, en cada caso, de sus miembros, de resolver la causa en justicia según su conciencia. Cuando el acusado es el gobernador o alguno de sus reemplazantes legales en ejercicio, el presidente de la Corte Suprema de Justicia preside la Cámara juzgadora, pero sin voto en el fallo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 148, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-150', lawId: 'const-santa-fe', number: '150', title: '', text: `Formulada la acusación, el Senado sustancia el juicio con arreglo a la ley, que debe asegurar amplia defensa al acusado. En ningún caso el juicio puede durar más de tres meses. Vencido este término sin que hubiere recaído sentencia, el acusado queda absuelto y, en su caso, reintegrado por ese solo hecho a sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 149, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-151', lawId: 'const-santa-fe', number: '151', title: '', text: `Ningún acusado puede ser declarado culpable sino por el voto de las dos terceras partes de los miembros presentes de la Cámara. La votación será nominal. El fallo condenatorio sólo dispone la destitución del acusado y aún su inhabilitación para ocupar cargos de la Provincia por tiempo determinado sin perjuicio de la responsabilidad del condenado ante la justicia ordinaria. El fallo absolutorio importa, en su caso, el reintegro de pleno derecho del acusado al ejercicio de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 150, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-152', lawId: 'const-santa-fe', number: '152', title: '', text: `Cuando el enjuiciado sea el gobernador o su reemplazante legal o un ministro del Poder Ejecutivo, las mayorías de dos tercios prescriptas en los artículos anteriores se computará sobre la totalidad de los miembros de las Cámaras.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 151, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-153', lawId: 'const-santa-fe', number: '153', title: '', text: `A los efectos de asegurar la continuidad sin interrupciones del juicio político, las Cámaras pueden prorrogar a ese solo fin sus sesiones ordinarias o ser convocadas a sesiones extraordinarias por acuerdo propio y a solicitud de una cuarta parte de los miembros de cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 152, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-154', lawId: 'const-santa-fe', number: '154', title: '', text: `Todo núcleo de población organizado como comunidad con vida propia se constituye como municipio y se gobierna por sí mismo con arreglo al ordenamiento jurídico. La Provincia reconoce a los municipios como base de su organización territorial y democrática; y garantiza su autonomía en los órdenes institucional, político, administrativo, económico y financiero, de conformidad con lo previsto en esta Constitución. La ley establece la delimitación territorial de los municipios y resuelve los casos de fusión y segregación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 153, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-155', lawId: 'const-santa-fe', number: '155', title: '', text: `La organización de los municipios y la determinación de los alcances y contenidos de la autonomía municipal son establecidos por el ordenamiento jurídico de acuerdo con las siguientes bases: 1) el gobierno municipal es democrático, representativo y republicano; 2) los municipios que tengan más de diez mil habitantes pueden dictar sus propias cartas orgánicas que deben contemplar: a) estructura institucional local conformada por un intendente, un Concejo Municipal y un órgano de control externo; b) procedimiento, órgano y mayorías agravadas para habilitar reformas a la Carta Orgánica; c) organización de la Administración Pública local con sus deberes, atribuciones y competencias para una adecuada gestión de los intereses locales; d) mecanismos de democracia directa y participación ciudadana; e) integración de regiones, áreas metropolitanas, asociación intermunicipal y supramunicipal; y articulación de competencias con la Provincia; y, f) todo lo referido a la mejor organización del gobierno local y de la comunidad en el marco de las previsiones del ordenamiento jurídico. Las cartas orgánicas se sancionan por una Convención Municipal, convocada al efecto por una ordenanza dictada por el Concejo Municipal. 3) los municipios que no tienen carta orgánica son organizados por la ley sobre la base de un gobierno local elegido directamente por el pueblo, cuya organización garantiza el cumplimiento de la función ejecutiva y la función legislativa, elegidos de la misma manera, por el mismo plazo y con representación proporcional y órganos o sistemas de control; 4) para determinar el número de habitantes se toma como base el sistema que determine la ley y en su defecto el último censo nacional; 5) la ley y las cartas orgánicas establecen las pautas y límites de las remuneraciones de los funcionarios municipales; 6) los titulares de los órganos con función ejecutiva y los integrantes de los órganos con función legislativa de todos los municipios duran cuatro años en sus funciones y son reelegibles una sola vez de manera consecutiva. Si han sido reelectos no pueden ser elegidos nuevamente sin el intervalo de un período; 7) las elecciones de autoridades municipales y el sistema electoral se rigen por ley provincial. Se realizan en forma conjunta con las elecciones de autoridades provinciales. En los municipios con más de veinte mil habitantes la renovación de los Concejos Municipales se realiza por mitades cada dos años; 8) los municipios tienen los deberes, atribuciones y competencias expresas e implícitas que se derivan de esta Constitución y de la naturaleza de sus funciones para la gestión de los intereses locales, con base en los principios de garantía de la autonomía, de subsidiariedad y de solidaridad horizontal y vertical; 9) las transferencias de competencias, servicios o funciones por parte de la Provincia a los municipios se deben realizar en forma concertada, con aprobación legislativa provincial y local y con la correspondiente asignación de recursos por parte de la Provincia; 10) las cartas orgánicas, toda ley que trate materia municipal, las relaciones de los municipios entre sí y con otros entes o ámbitos estatales se ajustan a los principios de colaboración, participación, auxilio, cooperación y coordinación; y, 11) la Provincia brinda asistencia técnica a los municipios para colaborar en la mejora de sus capacidades y para gestionar sus intereses locales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 154, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-156', lawId: 'const-santa-fe', number: '156', title: '', text: `El tesoro municipal se integra con: 1) los recursos propios establecidos y recaudados en el marco de sus competencias, con base en los principios de legalidad tributaria, igualdad, irretroactividad, no confiscatoriedad, equidad, proporcionalidad, capacidad contributiva, simplicidad, certeza y en armonía con los regímenes nacional y provincial. El régimen tributario puede inspirarse en criterios de progresividad; 2) la renta de los bienes propios; 3) el producido de la actividad económica y los servicios públicos que presten; 4) la coparticipación de tributos provinciales y nacionales, las transferencias automáticas y no automáticas provenientes del presupuesto nacional y provincial y los aportes de fondos especiales creados y regulados por ley; 5) donaciones, legados, subsidios, subvenciones, aportes especiales y otros ingresos no tributarios; y, 6) empréstitos y operaciones de crédito público de carácter interno y externo destinadas al financiamiento de obras de infraestructura, bienes de capital y conversión de deuda existente. Los servicios de la totalidad de la deuda a cancelarse en cada ejercicio no pueden comprometer más de la cuarta parte de los recursos del mismo. Las operaciones de crédito de los municipios deben contar con autorización por ordenanza municipal y de la Provincia. Los municipios de más de doscientos mil habitantes solo requerirán autorización provincial cuando la totalidad de los servicios de la deuda a cancelarse en cada ejercicio supere la doceava parte de los recursos del mismo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 155, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-157', lawId: 'const-santa-fe', number: '157', title: '', text: `La Provincia participa a la totalidad de los municipios un porcentaje de los recursos provenientes de la coparticipación federal y de los impuestos provinciales que recaude, de conformidad con un sistema de coordinación financiera que asegure la remisión automática de los fondos. La ley de coparticipación debe aprobarse por mayoría absoluta de la totalidad de integrantes de cada Cámara. Para la distribución primaria debe contemplar las competencias, servicios y funciones de la Provincia y del conjunto de los municipios, y para la distribución secundaria porcentajes de reparto basados en criterios objetivos y en los principios de proporcionalidad, eficiencia fiscal y redistribución solidaria, dando prioridad a un grado equivalente de desarrollo, a la constitución de áreas metropolitanas u otras instancias asociativas y a la calidad de vida e igualdad de oportunidades de sus habitantes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 156, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-158', lawId: 'const-santa-fe', number: '158', title: '', text: `La Provincia puede intervenir por ley o por decisión del Poder Ejecutivo en receso de la Legislatura, con cargo de dar cuenta inmediata a ésta, los municipios a los solos efectos de constituir sus autoridades en caso de acefalía total o de normalizar una situación institucional subvertida. En el caso de intervención por resolución del Poder Ejecutivo la Legislatura puede hacerla cesar al examinar los fundamentos de aquélla.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 157, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-159', lawId: 'const-santa-fe', number: '159', title: '', text: `Los municipios pueden celebrar convenios entre sí, con entes supramunicipales, con la Provincia, con otras provincias y sus municipios, con la Ciudad Autónoma de Buenos Aires y con la Nación con el fin de promover el desarrollo regional; organizar la prestación de servicios; la realización de obras públicas; implementar mecanismos de cooperación técnica y financiera; fortalecer capacidades institucionales y administrativas; planificar, ejecutar y evaluar políticas públicas de interés y utilidad común; y para concertar el ejercicio de facultades concurrentes e intereses comunes. A esos fines, pueden constituir regiones, áreas metropolitanas, regímenes de asociación intermunicipal y supramunicipal y crear organismos y entes que las organicen. Las áreas metropolitanas y regiones intermunicipales pueden constituirse como personas de derecho público de carácter no estatal, de conformidad con lo que prevé la ley y con la aprobación de los órganos legislativos de los respectivos municipios. Su instrumento constitutivo debe contemplar un gobierno democrático que garantice la participación estable de sus integrantes, la equidad en el manejo presupuestario, la sostenibilidad en el tiempo de los proyectos de interés común y la incorporación de la Provincia, que será necesaria cuando exista materia concurrente. La Provincia promueve la colaboración intermunicipal y la regionalización local y metropolitana. Los municipios pueden celebrar convenios con organismos internacionales de integración y cooperación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 158, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-160', lawId: 'const-santa-fe', number: '160', title: '', text: `Esta Constitución no puede ser reformada sino en virtud de una ley especial, sancionada con el voto de las dos terceras partes de los miembros de cada Cámara, que declare la necesidad de la reforma; y si fuere vetada, su promulgación requiere la insistencia legislativa por igual mayoría. La ley determina si la reforma debe ser total o parcial y, en este último caso, los artículos o la materia que hayan de reformarse. La reforma se hará por una Convención compuesta de diputados elegidos directamente por el pueblo en número igual al de los miembros del Poder Legislativo. Para ser convencional se requieren las mismas calidades que para ser diputado a la Legislatura. El cargo de convencional es compatible con cualquier otro nacional, provincial o municipal. Los convencionales gozan de las mismas inmunidades y remuneración de los legisladores, mientras ejerzan sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 159, segments: [], amendments: [] },
  { id: 'const-santa-fe-art-161', lawId: 'const-santa-fe', number: '161', title: '', text: `La ley especial que declare la necesidad de la reforma debe determinar, asimismo, las bases fundamentales de la elección, instalación y término de la Convención Reformadora. Queda reservada a ésta todo lo concerniente a su ordenamiento interno. La Convención puede prorrogar el término de su duración una sola vez y por la mitad del plazo fijado por la ley. Si vencido el plazo legal de duración la Convención no se hubiera expedido sobre todos los puntos susceptibles de reforma, se entenderá que ésta no se ha producido en parte alguna. En los casos de reforma parcial la Convención no puede pronunciarse sino sobre los artículos o la materia designados por la ley. La Convención no está obligada a modificar o suprimir las disposiciones de la Constitución si considera que no existe la necesidad de la reforma declarada por la ley. Firmantes Nómina de los Convencionales Reformadores que firmaron la Constitución: Balangione, Bastia, Baumgartner, Blanco, Boni, Borla, Brouwer, Calvo Capoccetti, Cattalini, Colombo, Corsalini, Cunha, De Ponti, Del Río, Diana, Dolzani, Enrico, Farías, Figueroa Casas, Fruh, Galdeano, Gallo Ambrosis, Garibaldi, Ghione, Giacomino, Giacosa, Giuliano, Giustiniani, Gramajo, Incicco, Lehmann Mantaras, Levin, Lewandowski, Machado, Mahmud, Marcon, Maroevich, Martínez Fernández, Masneri Calderari, Michlig, Monteverde, Motta,Olivera, Passarino, Peralta, Peyrano, Pirola, Pullaro, Rasetto, Ravena, Rodenas, Sanchez Lecumberri, Sclafani, Sosa, Svegliati, Tejeda, Traferri, Vidal. Savanco José Alberto DISPOSICIONES TRANSITORIAS Primera: Esta Constitución entrará en vigencia a partir del día de su publicación. Debe ser firmada por el presidente de la Convención Reformadora, los convencionales reformadores que quisieren hacerlo y refrendada por los secretarios parlamentarios y el secretario administrativo. Se remitirá un ejemplar auténtico a los Poderes Ejecutivo, Legislativo y Judicial y al Archivo Histórico y será publicada a través de los canales digitales de la Provincia y en el Boletín Oficial a fin de darle máxima difusión. Segunda: Los miembros de la Convención Reformadora, el gobernador, la vicegobernadora, sus ministros, la presidenta de la Cámara de Diputados y Diputadas, el presidente provisional del Senado y los demás legisladores, los integrantes de la Corte Suprema de Justicia, el procurador general, la fiscal general y la defensora general, el fiscal de Estado, los miembros del Tribunal de Cuentas, el defensor del pueblo y las autoridades de los gobiernos municipales dispondrán lo necesario para jurar esta Constitución dentro de los treinta días siguientes a su entrada en vigencia. Tercera: Las autoridades de la Convención y los secretarios de esta deberán, hasta el día 30 de septiembre de 2025, emitir todos los actos administrativos y tomar todas las medidas que sean necesarias para dar cumplimiento a todas las obligaciones que reconozcan como origen el funcionamiento y disolución de la Convención Reformadora. Cuarta: Hasta tanto la Legislatura sancione la ley electoral conforme a lo establecido en el artículo 56, se incorporarán al padrón las personas mayores de dieciséis años de edad y las personas extranjeras a los fines de que puedan ejercer el derecho de sufragio. Quinta: Hasta tanto se dicte la ley que determine la competencia judicial específica en materia electoral, continuará entendiendo en estos casos el Tribunal Electoral, de acuerdo con la normativa vigente al momento de sancionarse la presente Constitución. Sexta: Los mandatos de las autoridades provinciales elegidas por el voto popular que se encuentran en ejercicio al momento de sancionarse esta reforma no son considerados como primer período, con excepción de lo dispuesto para el gobernador y vicegobernador para quienes el mandato vigente se considera primer mandato. Séptima: Todas las leyes que deban dictarse de conformidad con lo dispuesto por esta Constitución serán sancionadas dentro del plazo máximo de dos años, contado a partir de su entrada en vigencia, salvo que se prevea expresamente un plazo menor. Hasta tanto se dicten, continúan vigentes las actuales. Octava: A partir de la entrada en vigencia de esta Constitución quien ocupa el cargo de procurador general pasa a titularizar la Procuración General creada en el artículo 119, con la misma jerarquía, remuneración y funciones que no hubiesen sido transferidas. Ocupará dicho cargo hasta que alcance los requisitos para acceder a la jubilación ordinaria o los setenta y cinco años de edad, lo que ocurra primero. Novena: A partir de la entrada en vigencia de esta Constitución los fiscales de materia extrapenal pasan a denominarse "procuradores", manteniendo la jerarquía y remuneración actual. A los procuradores que se designen de ahora en más, se les requerirá el acuerdo legislativo. Quedan exceptuados los que actualmente están en funciones en dichos cargos. Décima: Hasta la entrada en vigencia de la ley que regule el funcionamiento del Consejo de Selección del Poder Judicial y del Ministerio Público se aplica el sistema de selección de jueces, fiscales y defensores vigente a la fecha de entrada en vigor de esta Constitución. Décima primera: Los procedimientos de selección de jueces, de fiscales del Ministerio Público de la Acusación y de defensores del Servicio Público Provincial de Defensa Penal que se encuentren en trámite al momento de la entrada en vigencia de esta Constitución continúan hasta su finalización de acuerdo con la normativa vigente al inicio del procedimiento. Décima segunda: Hasta la entrada en vigencia de la ley que regule los procedimientos disciplinarios de jueces, procuradores, fiscales y defen- sores, los mismos se sustanciarán ante los órganos y se regirán por la normativa actualmente en vigor. Décima tercera: Lo previsto en los artículos relativos al enjuiciamiento de jueces, procuradores, fiscales y defensores resulta aplicable a partir de la vigencia de la ley que regule su funcionamiento. Décima cuarta: Las Defensorías Generales y del Ministerio Pupilar que dependen actualmente del procurador general mantienen su ubicación institucional, la forma de designación y remoción de sus integrantes y desempeñan sus funciones de conformidad con la normativa vigente, hasta la entrada en vigor de la ley que reglamente la organización del Ministerio Público de la Defensa. Décima quinta: La fiscal general, el auditor general de gestión y los fiscales regionales del Ministerio Público de la Acusación, la Defensora Provincial y los Defensores Regionales del Servicio Público Provincial de Defensa Penal continuarán en sus cargos hasta el vencimiento del mandato por el que fueron designados. El actual mandato de la fiscal general y de la defensora provincial se considerará primer período a los fines de una nueva designación. Décima sexta: Una ley debe contemplar todas aquellas medidas necesarias para la puesta en funcionamiento del Ministerio Público. El uso asignado y el destino de los inmuebles, espacios, oficinas, los bienes muebles y demás equipamiento que a la fecha de entrada en vigencia de esta Constitución estén afectados al Ministerio Público de la Acusación y al Servicio Público de Defensa Penal no podrá ser modificado sin la conformidad del Ministerio Público. Décima séptima: Los agentes que actualmente se desempeñan en el Ministerio Público de la Acusación y en el Servicio Público Provincial de Defensa Penal pasan a integrar el Ministerio Público con la entrada en vigencia de esta Constitución. Son traspasados de pleno derecho y de manera inmediata conjuntamente con sus respectivos cargos y las partidas presupuestarias que tienen asignadas. Se deben trasladar asimismo los cargos que se encuentren vacantes y que correspondan a dichos órganos. A los fines del traspaso, se toma en cuenta la planta existente al momento del inicio de esta Convención Reformadora (14/07/2025). Se les respeta la remuneración, funciones y ámbito geográfico de prestación de servicios y pautas que protejan el derecho a la carrera. Décima octava: Los agentes que actualmente se desempeñan en las defensorías generales y en el ministerio pupilar, dependientes del Procurador General, se trasladarán con sus respectivos cargos al Ministerio Público de la Defensa, tomándose en cuenta la planta existente al momento del inicio de esta Convención Reformadora (14/07/2025) y la que se agregue hasta el momento de producirse el efectivo traspaso, respetando la remuneración, funciones y ámbito geográfico de prestación de servicios. Una ley debe contemplar el plazo, las pautas del traspaso y la protección del derecho a la carrera. Décima novena: Los procesos judiciales alcanzados por las modificaciones al artículo 129 que estén iniciados en la Corte Suprema de Justicia al momento de entrada en vigencia de esta Constitución continuarán su trámite correspondiente hasta su culminación en ese órgano jurisdiccional. Vigésima: Los procesos de expropiación en los que la Provincia sea parte que se inicien con posterioridad a la entrada en vigencia de esta Constitución tramitarán en la justicia civil y comercial hasta que una ley regule la competencia. Vigésima primera: Los procesos contencioso administrativos y los recursos contra las decisiones del Tribunal de Cuentas tramitarán ante los órganos jurisdiccionales con competencia en materia contencioso administrativa hasta que una ley regule la materia. Vigésima segunda: Los Departamentos Ejecutivos podrán remitir a los Concejos Municipales un proyecto de ordenanza de declaración de necesidad del dictado de la Carta Orgánica convocando para tales fines a una Convención Estatuyente y pueden incluir en ella normas relativas a la implementación de las competencias propias de la autonomía establecidas constitucionalmente. Vigésima tercera: La unificación de las elecciones de los mandatos provinciales y municipales conforme lo previsto en el artículo 155 de esta Constitución comenzará a regir a partir del año 2035: A tales fines: 1) los titulares de Departamentos Ejecutivos que se elijan en el año 2029 serán electos por un período de seis años, por única vez; 2) todos los concejales de municipios con menos de veinte mil habitantes que fueron electos en el año 2025 desempeñarán su mandato hasta el año 2029. No se aplicarán los resultados de los sorteos realizados en función de las previsiones del artículo 23 de la Ley Orgánica de Municipalidades N° 2.756; y, 3) los concejales de municipios con menos de veinte mil habitantes que se elijan en el año 2029 desempeñarán su mandato hasta el año 2031, período que no será considerado a los fines de la aplicación de límites a las reelecciones. Vigésima cuarta: Los mandatos de las autoridades municipales y comunales que se encuentran en ejercicio al momento de sancionarse esta reforma no son considerados como primer período. Para las autoridades comunales cuyo mandato comienza en diciembre del año 2025 este no será considerado primer período. Para los titulares de Departamentos Ejecutivos y concejales cuyo mandato comienza en diciembre del año 2025 este será considerado como primer período. Vigésima quinta: La Legislatura deberá sancionar una nueva Ley Orgánica de Municipios de acuerdo con las disposiciones de esta Constitución, dentro del plazo de un año contado a partir de su entrada en vigencia. Vigésima sexta: Las ciudades que a la fecha de entrada en vigencia de esta Constitución se encuentran organizadas institucionalmente como municipios con un Departamento Ejecutivo y un Concejo Municipal y tengan menos de diez mil habitantes podrán decidir si mantienen su estructura institucional actual o adoptar la estructura institucional que contemple la nueva Ley Orgánica de Municipios. La decisión de adoptar la nueva estructura institucional debe ser formalizada a iniciativa del Departamento Ejecutivo, aprobada por ordenanza sancionada por dos tercios de integrantes de sus Concejos Municipales y comunicada a la Legislatura. Vigésimo séptima: La ley que establece el régimen de coparticipación previsto en el artículo 157 deberá dictarse dentro del plazo máximo de dos años contado a partir de la entrada en vigencia de la presente. No podrá modificarse en desmedro de la totalidad de los municipios la distribución de recursos vigente al momento de la sanción de esta reforma.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 160, segments: [], amendments: [] },
];
